const CentralStaffProfiles = () => {
  const navigate = useNavigate();
  const { profile: authProfile } = useAuth();

  const [profiles, setProfiles] = useState([]);
  const [loggedInFranchiseId, setLoggedInFranchiseId] = useState("");

  // --- DROPDOWN STATES ---
  const [companyList, setCompanyList] = useState([]);
  const [selectedCompany, setSelectedCompany] = useState("");
  const [franchiseList, setFranchiseList] = useState([]);
  const [searchFranchiseId, setSearchFranchiseId] = useState("");

  const [searchTerm, setSearchTerm] = useState("");
  const [companyDetails, setCompanyDetails] = useState(null);

  const [isModalOpen, setIsModalOpen] = useState(false);
  const [loading, setLoading] = useState(false);
  const [submitting, setSubmitting] = useState(false);
  const [isMobile, setIsMobile] = useState(window.innerWidth < 1024);
  const [expandedId, setExpandedId] = useState(null);
  const [editingId, setEditingId] = useState(null);
  const [showPassword, setShowPassword] = useState(false);

  const [formData, setFormData] = useState({
    name: "", staff_id: "", email: "", password: "", phone: "", address: ""
  });

  // 1. Initial Setup & Window Resize
  useEffect(() => {
    const handleResize = () => setIsMobile(window.innerWidth < 1024);
    window.addEventListener('resize', handleResize);

    if (authProfile?.franchise_id) {
      setLoggedInFranchiseId(authProfile.franchise_id);
      setSearchFranchiseId(authProfile.franchise_id);
      // Note: Auto-fetch will handle the data load since searchFranchiseId changed
    }

    fetchCompanyList();

    return () => window.removeEventListener('resize', handleResize);
  }, [authProfile]);

  // 2. Fetch Franchises when Company is Selected
  useEffect(() => {
    if (selectedCompany) {
      fetchFranchiseList(selectedCompany);
    } else {
      setFranchiseList([]);
      setSearchFranchiseId("");
    }
  }, [selectedCompany]);

  // 3. Auto-Fetch Profiles when Franchise ID is selected or changes
  useEffect(() => {
    if (searchFranchiseId) {
      fetchStaffProfiles(searchFranchiseId);
    } else {
      setProfiles([]); // Clear profiles if no franchise is selected
    }
  }, [searchFranchiseId]);

  // --- FETCH HELPERS ---
  const fetchCompanyList = async () => {
    try {
      const { data, error } = await supabase.from('companies').select('company_name');
      if (data && !error) {
        const uniqueCompanies = [...new Set(data.map(c => c.company_name).filter(Boolean))];
        setCompanyList(uniqueCompanies);
      }
    } catch (err) {
      console.error("Failed to load companies:", err);
    }
  };

  const fetchFranchiseList = async (companyName) => {
    try {
      const { data, error } = await supabase
        .from('profiles')
        .select('franchise_id')
        .eq('company', companyName)
        .neq('franchise_id', null);

      if (data && !error) {
        const uniqueFranchises = [...new Set(data.map(p => p.franchise_id).filter(Boolean))];
        setFranchiseList(uniqueFranchises);
      }
    } catch (err) {
      console.error("Failed to load franchises:", err);
    }
  };

  const fetchStaffProfiles = async (fid, isBackgroundRefresh = false) => {
    const cacheKey = `staff_profiles_${fid}`;
    if (!isBackgroundRefresh) {
      const cachedData = sessionStorage.getItem(cacheKey);
      if (cachedData) setProfiles(JSON.parse(cachedData));
      else setLoading(true);
    }

    try {
      const [ownerRes, staffRes] = await Promise.all([
        supabase.from('profiles').select('*').eq('franchise_id', fid).maybeSingle(),
        supabase.from('staff_profiles').select('*').eq('franchise_id', fid).order('created_at', { ascending: false })
      ]);

      const ownerData = ownerRes.data;
      const staffData = staffRes.data;

      if (ownerData?.company) {
        const { data: compData } = await supabase
          .from('companies')
          .select('*')
          .eq('company_name', ownerData.company)
          .maybeSingle();
        setCompanyDetails(compData);
      }

      let combined = [];
      if (ownerData) {
        combined.push({ ...ownerData, staff_id: "OWNER/ADMIN", isOwner: true, address: ownerData.address || "Branch Admin Office" });
      }
      if (staffData) combined = [...combined, ...staffData];

      setProfiles(combined);
      sessionStorage.setItem(cacheKey, JSON.stringify(combined));
    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setSubmitting(true);

    try {
      if (editingId) {
        const { error: profileError } = await supabase
          .from('staff_profiles')
          .update({
            name: formData.name,
            staff_id: formData.staff_id,
            email: formData.email.trim().toLowerCase(),
            phone: formData.phone,
            address: formData.address
          })
          .eq('id', editingId);

        if (profileError) throw profileError;

        if (formData.password?.trim()) {
          const { error: pwdErr } = await supabase.rpc('update_staff_password', {
            target_user_id: editingId,
            new_password: formData.password
          });
          if (pwdErr) throw pwdErr;
        }
        alert("✅ Updated Successfully");
      } else {
        const { data: edgeData, error: edgeError } = await supabase.functions.invoke('register-user', {
          body: {
            email: formData.email.trim().toLowerCase(),
            password: formData.password,
            metadata: {
              name: formData.name,
              role: 'staff',
              franchise_id: activeFranchiseId,
              staff_id: formData.staff_id,
              phone: formData.phone,
              address: formData.address,
            }
          }
        });

        if (edgeError || edgeData?.error) {
          throw new Error(edgeError?.message || edgeData?.error || "Failed to create staff user");
        }

        // Edge function returns authData in `edgeData.user`
        const authData = edgeData;

        const { error: dbError } = await supabase.from('staff_profiles').insert([{
          id: authData.user.id,
          name: formData.name,
          staff_id: formData.staff_id,
          email: formData.email.trim().toLowerCase(),
          phone: formData.phone,
          address: formData.address,
          franchise_id: searchFranchiseId
        }]);

        if (dbError) throw dbError;
        alert("✅ Staff Account Created Successfully");
      }

      fetchStaffProfiles(searchFranchiseId, true);
      closeModal();
    } catch (err) {
      alert("Error: " + err.message);
    } finally {
      setSubmitting(false);
    }
  };

  const handleOpenEdit = (profile) => {
    setEditingId(profile.id);
    setFormData({
      name: profile.name,
      staff_id: profile.staff_id,
      email: profile.email || "",
      password: "",
      phone: profile.phone,
      address: profile.address || ""
    });
    setIsModalOpen(true);
  };

  const closeModal = () => {
    setIsModalOpen(false);
    setEditingId(null);
    setFormData({ name: "", staff_id: "", email: "", password: "", phone: "", address: "" });
  };

  const filteredProfiles = profiles.filter(p =>
    p.name?.toLowerCase().includes(searchTerm.toLowerCase()) ||
    p.staff_id?.toLowerCase().includes(searchTerm.toLowerCase())
  );

  return (
    <div style={styles.page}>
      <header style={styles.header}>
        <div style={styles.headerInner}>
          <button onClick={() => navigate(-1)} style={styles.backBtn}>
            <ArrowLeft size={18} /> <span>Back</span>
          </button>
          <h1 style={styles.heading}>
            User <span style={{ color: GREEN }}>Management</span>
          </h1>
          <div style={styles.idBox}>ID : {loggedInFranchiseId || "---"}</div>
        </div>
      </header>

      <main style={{ ...styles.mainContent, padding: isMobile ? "0 15px 20px 15px" : "0 40px 20px 40px" }}>

        {/* --- REFINED FILTER CARD NO LOAD BUTTON --- */}
        <div style={{ ...styles.filterCard, padding: isMobile ? '16px' : '20px' }}>
          <div style={{ ...styles.filterForm, flexDirection: isMobile ? "column" : "row" }}>

            <div style={{ display: 'flex', alignItems: 'center', gap: '8px', width: isMobile ? '100%' : 'auto', minWidth: '130px' }}>
              <Building2 size={18} color={GREEN} />
              <span style={styles.filterLabel}>Load Branch:</span>
            </div>

            <div style={{ display: 'flex', gap: '12px', width: "100%", flex: 1, flexDirection: isMobile ? "column" : "row" }}>

              {/* Company Dropdown */}
              <div style={{ position: 'relative', flex: 1 }}>
                <select
                  value={selectedCompany}
                  onChange={(e) => {
                    setSelectedCompany(e.target.value);
                    setSearchFranchiseId(""); // Reset franchise ID when company changes
                  }}
                  style={styles.dropdownSelect}
                >
                  <option value="" disabled>Select Company</option>
                  {companyList.map(comp => (
                    <option key={comp} value={comp}>{comp}</option>
                  ))}
                </select>
                <ChevronDown size={16} color="#94a3b8" style={styles.dropdownArrow} />
              </div>

              {/* Franchise ID Dropdown */}
              <div style={{ position: 'relative', flex: 1 }}>
                <select
                  value={searchFranchiseId}
                  onChange={(e) => setSearchFranchiseId(e.target.value)}
                  disabled={!selectedCompany || franchiseList.length === 0}
                  style={{
                    ...styles.dropdownSelect,
                    backgroundColor: (!selectedCompany || franchiseList.length === 0) ? '#f8fafc' : 'white',
                    cursor: (!selectedCompany || franchiseList.length === 0) ? 'not-allowed' : 'pointer'
                  }}
                >
                  <option value="" disabled>
                    {!selectedCompany ? "Select Company First" : (franchiseList.length === 0 ? "No Franchises Found" : "Select Franchise ID")}
                  </option>
                  {franchiseList.map(fid => (
                    <option key={fid} value={fid}>{fid}</option>
                  ))}
                </select>
                <ChevronDown size={16} color="#94a3b8" style={styles.dropdownArrow} />
              </div>

            </div>
          </div>
        </div>

        <div style={{ ...styles.actionRow, gap: isMobile ? '8px' : '15px' }}>
          <div style={{ ...styles.searchContainer, flex: 1 }}>
            <Search size={18} style={styles.searchIcon} color="#94a3b8" />
            <input
