                                            <td className="px-6 py-4 whitespace-nowrap"> <div className="font-black text-xs text-black">₹{item.price}</div> <div className="text-[9px] font-bold text-slate-400">{item.gst_rate}% ({item.sales_tax_inc})</div> </td>
