                                    <div className="md:col-span-2">
                                        <label className="text-[10px] font-bold uppercase text-black block mb-1">Tax Mode</label>
                                        <TaxToggle value={formData.purchase_tax_inc} onSelect={(val) => setFormData({ ...formData, purchase_tax_inc: val })} brandColor={BRAND_COLOR} />
                                    </div>

                                    {/* ROW 2: GST | Total Purchase */}
                                    <div className="md:col-span-1">
                                        <label className="text-[10px] font-bold uppercase text-black block mb-1">GST Rate (%)</label>
                                        <input type="number" name="gst_rate" value={formData.gst_rate} onChange={handleInput} className="w-full bg-slate-50 rounded-lg border border-slate-200 px-3 h-[42px] outline-none font-bold text-black text-sm" placeholder="18" />
                                    </div>
                                    <div className="md:col-span-1">
                                        <label className="text-[10px] font-bold uppercase text-slate-400 block mb-1">Total Purchase</label>
                                        <div className="flex items-center px-3 h-[42px] rounded-lg border border-slate-100 bg-slate-50 text-slate-600 font-bold text-sm">
                                            ₹ {calculateWithTax(formData.purchase_price, formData.purchase_tax_inc)}
                                        </div>
                                    </div>
                                    <div className="md:col-span-2"></div>

                                    {/* ROW 3: Sales Price | Tax Mode | Total Sales */}
                                    <div className="md:col-span-1">
                                        <label className="text-[10px] font-bold uppercase text-black block mb-1">Sales Price</label>
                                        <input type="number" name="price" value={formData.price} onChange={handleInput} className="w-full bg-slate-50 rounded-lg border border-slate-200 px-3 h-[42px] outline-none font-black text-black text-sm" placeholder="0.00" />
                                    </div>
                                    <div className="md:col-span-2">
                                        <label className="text-[10px] font-bold uppercase text-black block mb-1">Tax Mode</label>
                                        <TaxToggle value={formData.sales_tax_inc} onSelect={(val) => setFormData({ ...formData, sales_tax_inc: val })} brandColor={BRAND_COLOR} />
                                    </div>
                                    <div className="md:col-span-1">
                                        <label className="text-[10px] font-bold uppercase text-slate-400 block mb-1">Total Sales</label>
                                        <div className="flex items-center px-3 h-[42px] rounded-lg border border-emerald-100 bg-emerald-50 text-emerald-700 font-bold text-sm">
                                            ₹ {calculateWithTax(formData.price, formData.sales_tax_inc)}
                                        </div>
                                    </div>

                                </div>

                                {/* --- SECTION 4: MRP --- */}
                                <div className="md:col-span-3 border-b border-slate-100 pb-2 mt-4"><h3 className="text-[11px] font-black uppercase text-black tracking-[0.2em] flex items-center gap-2"><Tag size={12} /> Retail Pricing</h3></div>

                                <div className="md:col-span-1">
                                    <label className="text-[10px] font-bold uppercase text-black block mb-1">Maximum Retail Price (MRP)</label>
                                    <div className="relative h-[42px]">
                                        <input type="number" name="mrp" value={formData.mrp} onChange={handleInput} className="w-full h-full bg-slate-50 rounded-lg border border-slate-200 px-3 outline-none font-black text-black text-sm" placeholder="0.00" />
                                        <span className="absolute right-3 top-1/2 -translate-y-1/2 text-[10px] font-bold text-slate-400">INR</span>
                                    </div>
                                </div>

                            </div>
                            <div className="h-20 md:hidden"></div>
                        </div>

                        <div className="p-4 md:p-6 bg-white border-t border-slate-100 flex gap-3 flex-shrink-0 z-20 shadow-[0_-4px_6px_-1px_rgba(0,0,0,0.05)]">
                            <button onClick={() => setShowModal(false)} className="flex-1 py-3.5 md:py-4 rounded-xl border border-slate-200 font-black text-[11px] uppercase tracking-widest text-black hover:bg-slate-50 transition-all">Discard</button>
                            <button onClick={saveItem} disabled={loading} className="flex-[2] py-3.5 md:py-4 text-white font-black uppercase tracking-widest text-xs rounded-xl shadow-lg transition-all active:scale-95 disabled:bg-slate-300 flex items-center justify-center gap-2" style={{ backgroundColor: BRAND_COLOR }}>
                                {loading ? 'Saving...' : 'Finalize & Save'}
                            </button>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
}

export default CentralStockMaster;

import React, { useState, useEffect, useMemo } from "react";
import { useNavigate } from "react-router-dom";
import {
  ArrowLeft, Search, Plus, Edit2, Trash2, X, Users, RefreshCw, Layers, Filter, AlertCircle, Building2, ChevronDown
} from "lucide-react";
import { supabase } from "../../supabase/supabaseClient";
import { useAuth } from "../../context/AuthContext"; // IMPORTED AUTH CONTEXT
import { BRAND_GREEN } from "../../utils/theme";

// --- THEME ---
const BRAND_COLOR = BRAND_GREEN;

// --- UTILITY STYLES (Injected for Scrollbar Hiding) ---
const CustomStyles = () => (
  <style>{`
    .no-scrollbar::-webkit-scrollbar { display: none; }
    .no-scrollbar { -ms-overflow-style: none; scrollbar-width: none; }
  `}</style>
);

const CentralVendors = () => {
  const navigate = useNavigate();
  const { profile: authProfile } = useAuth(); // EXTRACTED PROFILE

  // --- DROPDOWN & AUTH STATE ---
  const [companyList, setCompanyList] = useState([]);
  const [selectedCompany, setSelectedCompany] = useState(() => sessionStorage.getItem("vendor_central_selectedCompany") || "");

  const [vendors, setVendors] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);

  // Filters
  const [searchTerm, setSearchTerm] = useState("");
  const [selectedCategory, setSelectedCategory] = useState("All");

  // Modal
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [submitting, setSubmitting] = useState(false);
  const [editingId, setEditingId] = useState(null);

  // Form Data
  const [formData, setFormData] = useState({
    name: "",
    category: "",
    phone: "",
    address: "",
    gst: ""
  });

  // --- LIFECYCLE ---
  useEffect(() => {
    fetchUserData();
    fetchCompanyList();
  }, []);

  // Save dropdown state to session storage
  useEffect(() => {
    sessionStorage.setItem("vendor_central_selectedCompany", selectedCompany);
  }, [selectedCompany]);

  // Auto-Fetch vendors when Company changes
  useEffect(() => {
    if (selectedCompany) {
      fetchVendors(selectedCompany);
    } else {
      setVendors([]);
    }
  }, [selectedCompany]);


  // --- DATA FETCHING ---
  const fetchUserData = async () => {
    try {
      const { data: { user } } = await supabase.auth.getUser();
      if (!user) {
        navigate("/login");
        return;
      }
    } catch (err) {
      console.error("[DEBUG - AUTH] Catch block hit:", err);
      setError("Failed to verify user session.");
    }
  };

  const fetchCompanyList = async () => {
    try {
      const { data, error } = await supabase.from('companies').select('company_name');
      if (data && !error) {
        const uniqueCompanies = [...new Set(data.map(c => c.company_name).filter(Boolean))];
        setCompanyList(uniqueCompanies);
      }
    } catch (err) {
      console.error("Failed to load companies:", err);
    }
  };

  const fetchVendors = async (companyName) => {
    setLoading(true);
    setError(null);
    try {
      // We use the company name as the franchise_id for central vendors
      const { data, error } = await supabase
        .from('vendors')
        .select('*')
        .eq('company_name', companyName)
        .order('created_at', { ascending: false });

      if (error) throw error;
      setVendors(data || []);
    } catch (err) {
      console.error("[DEBUG - FETCH] Catch block hit:", err.message);
      setError("Could not load vendors. Please check your connection.");
    } finally {
      setLoading(false);
    }
  };

  // --- HANDLERS ---
  const handleOpenAdd = () => {
    if (!selectedCompany) return alert("Please select a Company first.");
    setEditingId(null);
    setFormData({ name: "", category: "", phone: "", address: "", gst: "" });
    setIsModalOpen(true);
  };

  const handleOpenEdit = (vendor) => {
    setEditingId(vendor.id);
    setFormData({
      name: vendor.name,
      category: vendor.category || "",
      phone: vendor.phone,
      address: vendor.address || "",
      gst: vendor.gst || ""
    });
    setIsModalOpen(true);
  };

  const handleDelete = async (id) => {
    if (!window.confirm("Are you sure you want to delete this vendor? This cannot be undone.")) return;

    try {
      const response = await supabase.from('vendors').delete().eq('id', id).select();

      if (response.error) throw response.error;

      if (!response.data || response.data.length === 0) {
        throw new Error("RLS Silent Failure: The database refused to delete the row.");
      }

      setVendors(prev => prev.filter(v => v.id !== id));
    } catch (err) {
      console.error("[DEBUG - CATCH BLOCK ERROR]", err);
      alert(`DELETE FAILED!\nMessage: ${err.message || 'Unknown Error'}`);
    }
  };

  const handlePhoneChange = (e) => {
    const val = e.target.value.replace(/\D/g, '');
    if (val.length <= 10) {
      setFormData({ ...formData, phone: val });
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!selectedCompany) return alert("System Error: Company missing.");

    if (formData.phone.length !== 10) {
      alert("Please enter a valid 10-digit mobile number.");
      return;
    }

    setSubmitting(true);

    try {
      const payload = {
        name: formData.name.trim(),
        category: formData.category.trim(),
        phone: formData.phone.trim(),
        address: formData.address.trim(),
        gst: formData.gst.trim().toUpperCase(),
        company_name: selectedCompany
      };

      if (!payload.name || !payload.phone) {
        throw new Error("Name and Phone are required.");
      }

      if (editingId) {
        const { error } = await supabase.from('vendors').update(payload).eq('id', editingId);
        if (error) throw error;
      } else {
        const { error } = await supabase.from('vendors').insert([payload]);
        if (error) throw error;
      }

      setIsModalOpen(false);
      fetchVendors(selectedCompany);
    } catch (err) {
      console.error("[DEBUG - SUBMIT CATCH]", err);
      alert(`Save failed: ${err.message}`);
    } finally {
      setSubmitting(false);
    }
  };

  const openWhatsApp = (phone) => {
    if (!phone) return alert("No phone number available");
    let cleanNumber = phone.replace(/[^0-9]/g, '');
    if (cleanNumber.length === 10) cleanNumber = "91" + cleanNumber;
    window.open(`https://api.whatsapp.com/send?phone=${cleanNumber}`, '_blank', 'noopener,noreferrer');
  };

  // --- MEMOIZED DATA ---
  const uniqueCategories = useMemo(() => {
    if (!vendors) return ["All"];
    const cats = new Set(vendors.map(v => v.category).filter(c => c && c.trim() !== ""));
    return ["All", ...Array.from(cats).sort()];
  }, [vendors]);

  const filteredVendors = useMemo(() => {
    return vendors.filter(v => {
      const vendorCat = v.category || "";
      if (selectedCategory !== "All" && vendorCat !== selectedCategory) return false;

      const searchLower = searchTerm.toLowerCase();
      const matchText = v.name.toLowerCase().includes(searchLower) ||
        vendorCat.toLowerCase().includes(searchLower) ||
        (v.phone && v.phone.includes(searchTerm));
      if (!matchText) return false;

      return true;
    });
  }, [vendors, searchTerm, selectedCategory]);

  return (
    <div className="h-[100dvh] w-full flex flex-col bg-slate-50 font-sans text-black overflow-hidden relative">
      <CustomStyles />

      {/* --- HEADER --- */}
      <div className="flex-none bg-white shadow-sm z-30 pt-safe-top">
        <div className="border-b border-slate-200 px-4 md:px-6 py-3 md:py-4">
          <div className="w-full flex items-center justify-between gap-2">
            <button onClick={() => navigate(-1)} className="flex items-center gap-1 text-black hover:opacity-70 font-bold transition text-xs md:text-base flex-shrink-0">
              <ArrowLeft size={18} /> <span>Back</span>
            </button>
            <h1 className="text-xs md:text-2xl font-black uppercase text-black text-center flex-1 truncate px-2">
              Company <span style={{ color: BRAND_COLOR }}>Vendors</span>
            </h1>

            {/* UPDATED: Displays ID of logged in user */}
            <div className="flex items-center flex-shrink-0">
              <div className="bg-slate-50 px-3 py-1.5 rounded-lg border border-slate-200 shadow-sm flex items-center gap-2">
                <span className="text-[10px] md:text-xs text-slate-400 font-black uppercase tracking-wider">ID :</span>
                <span className="text-[10px] md:text-sm font-bold text-slate-700 font-mono">
                  {authProfile?.franchise_id || authProfile?.staff_id || "---"}
                </span>
              </div>
            </div>
          </div>
        </div>

        {/* --- COMPANY DROPDOWN & ACTIONS --- */}
        <div className="w-full px-4 md:px-6 py-4 pb-0">

          <div className="flex flex-col md:flex-row items-center gap-3 w-full mb-3 bg-white p-3 md:p-4 rounded-xl border border-slate-200 shadow-sm">
            <div className="flex items-center gap-2 text-[#065f46] font-bold text-sm w-full md:w-auto flex-shrink-0">
              <Building2 size={18} />
              <span className="whitespace-nowrap">Select Company:</span>
            </div>

            <div className="relative flex-1 w-full">
              <select
                value={selectedCompany}
                onChange={(e) => setSelectedCompany(e.target.value)}
                className="w-full appearance-none bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 text-sm font-bold text-[#065f46] outline-none focus:border-[#065f46] cursor-pointer"
              >
                <option value="" disabled>-- Choose a Company --</option>
                {companyList.map(c => <option key={c} value={c}>{c}</option>)}
              </select>
              <ChevronDown size={16} className="absolute right-4 top-1/2 -translate-y-1/2 text-slate-400 pointer-events-none" />
            </div>
          </div>

          <div className="flex flex-col lg:flex-row gap-3 mb-3">
            <div className="relative flex-1 min-w-0">
              <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
              <input
                type="text"
                placeholder="Search vendors..."
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
                className="w-full pl-11 pr-4 py-3 bg-slate-50 border border-slate-200 rounded-xl outline-none focus:bg-white focus:border-[#065f46] text-sm font-semibold shadow-sm transition-all"
              />
            </div>

            <div className="flex items-center justify-end overflow-x-auto no-scrollbar pb-1 lg:pb-0">
              <button onClick={handleOpenAdd}
                disabled={!selectedCompany}
                className="h-[46px] text-white px-4 md:px-5 rounded-xl font-bold uppercase text-[10px] md:text-xs flex items-center gap-2 shadow-md flex-shrink-0 whitespace-nowrap transition-all active:scale-95 disabled:opacity-50 disabled:cursor-not-allowed"
                style={{ backgroundColor: BRAND_COLOR }}>
                <span>Add Vendor</span>
                <Plus size={16} />
              </button>
            </div>
          </div>

          {/* Categories */}
          {selectedCompany && (
            <div className="flex gap-2 overflow-x-auto pb-3 border-t border-slate-100 pt-3 no-scrollbar touch-pan-x">
              {uniqueCategories.map((cat) => (
                <button key={cat} onClick={() => setSelectedCategory(cat)}
                  className={`px-4 py-1.5 rounded-full text-[10px] md:text-xs font-bold border transition-all whitespace-nowrap flex items-center gap-1
                      ${selectedCategory === cat ? "text-white shadow-md" : "bg-white text-slate-600 border-slate-200 hover:border-slate-300"}`}
                  style={selectedCategory === cat ? { backgroundColor: BRAND_COLOR, borderColor: BRAND_COLOR } : {}}>
                  {selectedCategory === cat && <Layers size={12} />}
                  {cat}
                </button>
              ))}
            </div>
          )}
        </div>
      </div>

      {/* --- CONTENT LIST --- */}
      <div className="flex-grow overflow-hidden relative bg-slate-50">
        <div className="absolute inset-0 overflow-y-auto px-4 md:px-6 pb-24 pt-2 no-scrollbar">
          {loading ? (
            <div className="flex flex-col items-center justify-center h-64 text-slate-400 gap-3 animate-pulse">
              <RefreshCw className="animate-spin" size={32} />
              <span className="text-xs font-bold uppercase tracking-wider">Syncing Vendors...</span>
            </div>
          ) : error ? (
            <div className="flex flex-col items-center justify-center h-64 text-red-500 gap-3">
              <AlertCircle size={32} />
              <span className="text-sm font-bold">{error}</span>
              <button onClick={() => fetchVendors(selectedCompany)} className="text-xs underline">Try Again</button>
            </div>
          ) : !selectedCompany ? (
            <div className="flex flex-col items-center justify-center h-64 text-slate-400 gap-3">
              <div className="bg-slate-100 p-4 rounded-full">
                <Building2 size={32} />
              </div>
              <span className="text-xs font-bold uppercase tracking-wider">Select a company to view vendors</span>
            </div>
          ) : filteredVendors.length === 0 ? (
            <div className="flex flex-col items-center justify-center h-64 text-slate-400 gap-3">
              <div className="bg-slate-100 p-4 rounded-full">
                <Filter size={32} />
              </div>
              <span className="text-xs font-bold uppercase tracking-wider">No vendors found</span>
            </div>
          ) : (
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-3">
              {filteredVendors.map((vendor) => (
                <div key={vendor.id} className="bg-white p-4 rounded-xl shadow-sm border border-slate-200 flex flex-col gap-3 hover:border-[#065f46]/30 transition-all hover:shadow-md">
                  <div className="flex justify-between items-start">
                    <div className="flex items-start gap-3 flex-1 min-w-0">
                      <div className="w-10 h-10 rounded-full bg-slate-100 flex items-center justify-center text-slate-500 font-bold flex-shrink-0 text-sm">
                        {vendor.name.charAt(0).toUpperCase()}
                      </div>
                      <div className="flex-1 min-w-0">
                        <div className="font-black text-sm text-black truncate" title={vendor.name}>{vendor.name}</div>
                        <div className="text-[10px] bg-slate-100 inline-block px-2 py-0.5 rounded text-slate-500 font-bold uppercase mt-1 truncate max-w-full">
                          {vendor.category || "No Category"}
                        </div>
                      </div>
                    </div>
                    <button onClick={() => openWhatsApp(vendor.phone)} className="p-2 bg-[#25D366] text-white rounded-lg shadow-sm hover:opacity-90 transition-opacity flex-shrink-0 flex items-center justify-center w-[36px] h-[36px]">
                      <svg viewBox="0 0 24 24" width="20" height="20" fill="currentColor">
                        <path d="M17.472 14.382c-.297-.149-1.758-.867-2.03-.967-.273-.099-.471-.148-.67.15-.197.297-.767.966-.94 1.164-.173.199-.347.223-.644.075-.297-.15-1.255-.463-2.39-1.475-.883-.788-1.48-1.761-1.653-2.059-.173-.297-.018-.458.13-.606.134-.133.298-.347.446-.52.149-.174.198-.298.298-.497.099-.198.05-.371-.025-.52-.075-.149-.669-1.612-.916-2.207-.242-.579-.487-.5-.669-.51a12.8 12.8 0 0 0-.57-.01c-.198 0-.52.074-.792.372-.272.297-1.04 1.016-1.04 2.479 0 1.462 1.065 2.875 1.213 3.074.149.198 2.096 3.2 5.077 4.487.709.306 1.262.489 1.694.625.712.227 1.36.195 1.871.118.571-.085 1.758-.719 2.006-1.413.248-.694.248-1.289.173-1.413-.074-.124-.272-.198-.57-.347m-5.421 7.403h-.004a9.87 9.87 0 0 1-5.031-1.378l-.361-.214-3.741.982.998-3.648-.235-.374a9.86 9.86 0 0 1-1.51-5.26c.001-5.45 4.436-9.884 9.888-9.884 2.64 0 5.122 1.03 6.988 2.898a9.82 9.82 0 0 1 2.893 6.994c-.003 5.45-4.437 9.884-9.885 9.884m8.413-18.297A11.815 11.815 0 0 0 12.05 0C5.495 0 .16 5.335.157 11.892c0 2.096.547 4.142 1.588 5.945L.057 24l6.305-1.654a11.882 11.882 0 0 0 5.683 1.448h.005c6.554 0 11.89-5.335 11.893-11.893a11.821 11.821 0 0 0-3.48-8.413Z" />
                      </svg>
                    </button>
                  </div>
                  <div className="flex justify-between items-center text-xs font-bold border-t border-slate-50 pt-3 mt-auto">
                    <span className="text-slate-400 uppercase truncate mr-2">Contact: {vendor.phone}</span>
                    <div className="flex gap-2 flex-shrink-0">
                      <button onClick={() => handleOpenEdit(vendor)} className="p-2 text-slate-600 hover:text-[#065f46] hover:bg-slate-50 rounded-lg transition-colors"><Edit2 size={16} /></button>
                      <button onClick={() => handleDelete(vendor.id)} className="p-2 text-red-400 hover:text-red-600 hover:bg-red-50 rounded-lg transition-colors"><Trash2 size={16} /></button>
                    </div>
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>
      </div>

      {/* --- MODAL --- */}
      {isModalOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center px-4">
          <div className="absolute inset-0 bg-black/60 backdrop-blur-sm" onClick={() => setIsModalOpen(false)}></div>

          <div className="bg-white w-full max-w-md rounded-2xl shadow-2xl flex flex-col relative z-10 animate-in zoom-in-95 duration-200">
            <div className="p-5 border-b border-slate-100 flex justify-between items-center">
              <h2 className="font-black uppercase tracking-widest text-black flex items-center gap-2 text-sm md:text-base">
                <Users size={18} />
                {editingId ? "Edit Vendor" : "Add New Vendor"}
              </h2>
              <button onClick={() => setIsModalOpen(false)} className="p-2 hover:bg-slate-100 rounded-full transition-colors text-slate-500 hover:text-black">
                <X size={20} />
              </button>
            </div>

            <form onSubmit={handleSubmit} className="p-6 flex flex-col gap-4 overflow-y-auto max-h-[80vh] no-scrollbar">

              {/* Context Banner */}
              <div className="bg-slate-50 border border-slate-200 p-3 rounded-xl flex items-center gap-2 mb-2">
                <Building2 size={16} className="text-slate-400" />
                <span className="text-xs font-bold text-slate-600">Company: <span style={{ color: BRAND_COLOR }}>{selectedCompany}</span></span>
              </div>

              <div>
                <input
                  required
                  value={formData.name}
                  onChange={e => setFormData({ ...formData, name: e.target.value })}
                  placeholder="Vendor Name*"
                  className="w-full bg-slate-50 rounded-xl border border-slate-200 p-4 outline-none focus:border-[#065f46] focus:ring-1 focus:ring-[#065f46] font-bold text-sm transition-all"
                />
              </div>
              <div>
                <input
                  value={formData.category}
                  onChange={e => setFormData({ ...formData, category: e.target.value })}
                  placeholder="Category (e.g. Tea Powder)"
                  className="w-full bg-slate-50 rounded-xl border border-slate-200 p-4 outline-none focus:border-[#065f46] focus:ring-1 focus:ring-[#065f46] text-sm transition-all"
                />
              </div>
              <div>
                <input
                  required
                  type="tel"
                  value={formData.phone}
                  onChange={handlePhoneChange}
                  maxLength={10}
                  placeholder="Mobile Number (10 digits)*"
                  className="w-full bg-slate-50 rounded-xl border border-slate-200 p-4 outline-none focus:border-[#065f46] focus:ring-1 focus:ring-[#065f46] font-mono text-sm transition-all"
                />
              </div>
              <div>
                <input
                  value={formData.gst}
                  onChange={e => setFormData({ ...formData, gst: e.target.value })}
                  placeholder="Vendor GST (Optional)"
                  className="w-full bg-slate-50 rounded-xl border border-slate-200 p-4 outline-none focus:border-[#065f46] focus:ring-1 focus:ring-[#065f46] text-sm transition-all uppercase"
                />
              </div>
              <div>
                <textarea
                  value={formData.address}
                  onChange={e => setFormData({ ...formData, address: e.target.value })}
                  placeholder="Address (Optional)"
                  className="w-full bg-slate-50 rounded-xl border border-slate-200 p-4 outline-none focus:border-[#065f46] focus:ring-1 focus:ring-[#065f46] text-sm transition-all resize-none h-24"
                />
              </div>

              <button type="submit" disabled={submitting} className="w-full py-4 text-white font-black uppercase rounded-xl shadow-lg hover:shadow-xl transition-all active:scale-95 disabled:bg-slate-300 disabled:scale-100 disabled:shadow-none mt-2 text-sm tracking-wide" style={{ backgroundColor: BRAND_COLOR }}>
                {submitting ? 'Saving...' : 'Save Vendor'}
              </button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default CentralVendors;

import { useEffect, useState, useMemo } from "react";
import { supabase } from "../../supabase/supabaseClient";
import { useNavigate } from "react-router-dom";
import {
  FiCheckCircle, FiClock, FiList, FiX, FiInbox
} from "react-icons/fi";
import { ArrowLeft, Search, Calendar, RotateCcw } from "lucide-react";

const BRAND_COLOR = "rgb(0, 100, 55)";

const FranchiseReplies = () => {
  const navigate = useNavigate();
  const [requests, setRequests] = useState([]);
  const [loading, setLoading] = useState(true);
  const [searchTerm, setSearchTerm] = useState("");
  const [profile, setProfile] = useState(null);

  // Modal & Selection States
  const [selectedGroup, setSelectedGroup] = useState(null);
  const [selectedItemIds, setSelectedItemIds] = useState([]);

  // Filter States
  const [isRange, setIsRange] = useState(false);
  const [singleDate, setSingleDate] = useState(new Date().toISOString().split('T')[0]);
  const [dateRange, setDateRange] = useState({ start: "", end: "" });

  useEffect(() => {
    fetchProfile();
    fetchRequests();

    const channel = supabase
      .channel('table-db-changes')
      .on(
        'postgres_changes',
        {
          event: '*',
          schema: 'public',
          table: 'stock_requests',
        },
        (payload) => {
          fetchRequests();
        }
      )
      .subscribe();

    return () => {
      supabase.removeChannel(channel);
    };
  }, []);

  const fetchProfile = async () => {
    try {
      const { data: { user } } = await supabase.auth.getUser();
      if (user) {
        const { data } = await supabase.from("profiles").select("franchise_id").eq("id", user.id).single();
        setProfile(data);
      }
    } catch (e) {
      console.error("Profile fetch error", e);
    }
  };

  const fetchRequests = async () => {
    if (requests.length === 0) setLoading(true);

    try {
      const { data, error } = await supabase
        .from("stock_requests")
        .select("*")
        .order("created_at", { ascending: false });

      if (error) throw error;
      setRequests(data || []);
    } catch (error) {
      console.error("Error fetching requests:", error.message);
    } finally {
      setLoading(false);
    }
  };

  const groupedRequests = useMemo(() => {
    const groups = {};
    if (!requests) return [];

    requests.forEach((req) => {
      if (!req.created_at) return;

      const dateObj = new Date(req.created_at);
      const minuteKey = `${req.franchise_id}-${dateObj.getFullYear()}-${dateObj.getMonth()}-${dateObj.getDate()}-${dateObj.getHours()}-${dateObj.getMinutes()}`;

      if (!groups[minuteKey]) {
        groups[minuteKey] = {
          ...req,
          displayItems: [{ id: req.id, name: req.item_name, status: req.status }],
        };
      } else {
        groups[minuteKey].displayItems.push({ id: req.id, name: req.item_name, status: req.status });
      }
    });
    return Object.values(groups);
  }, [requests]);

  const toggleItemSelection = (id) => {
    setSelectedItemIds(prev =>
      prev.includes(id) ? prev.filter(itemId => itemId !== id) : [...prev, id]
    );
  };

  const updateItemStatus = async (ids, newStatus) => {
    if (ids.length === 0) return;

    const previousRequests = [...requests];

    setRequests(prev => prev.map(req =>
      ids.includes(req.id) ? { ...req, status: newStatus } : req
    ));

    setSelectedItemIds([]);
    if (selectedGroup) setSelectedGroup(null);

    try {
      const { error } = await supabase
        .from("stock_requests")
        .update({ status: newStatus })
        .in("id", ids);

      if (error) throw error;

    } catch (err) {
      setRequests(previousRequests);
      alert("Failed to update status. Please try again.");
    }
  };

  const resetFilters = () => {
    setSearchTerm("");
    setIsRange(false);
    setSingleDate(new Date().toISOString().split('T')[0]);
    setDateRange({ start: "", end: "" });
    fetchRequests();
  };

  const filteredRequests = useMemo(() => {
    return groupedRequests.filter(req => {
      const matchesSearch = req.displayItems.some(item => item.name?.toLowerCase().includes(searchTerm.toLowerCase())) ||
        req.franchise_id?.toLowerCase().includes(searchTerm.toLowerCase());

      const reqDate = new Date(req.created_at).toISOString().split('T')[0];
      let matchesDate = true;

      if (isRange) {
        if (dateRange.start && dateRange.end) {
          matchesDate = reqDate >= dateRange.start && reqDate <= dateRange.end;
        }
      } else {
        if (singleDate) matchesDate = reqDate === singleDate;
      }
      return matchesSearch && matchesDate;
    });
  }, [groupedRequests, searchTerm, isRange, singleDate, dateRange]);

  return (
    <div className="min-h-screen bg-slate-50 font-sans text-black relative selection:bg-black selection:text-white pb-20">
      {/* MODAL */}
      {selectedGroup && (
        <div className="fixed inset-0 z-[100] flex items-end sm:items-center justify-center p-0 sm:p-4 bg-black/60 backdrop-blur-sm animate-in fade-in duration-200">
          <div className="bg-white w-full max-w-md rounded-t-[2.5rem] sm:rounded-[2.5rem] border-2 border-slate-100 shadow-2xl overflow-hidden flex flex-col max-h-[90vh]">
            <div className="p-6 border-b-2 border-slate-50 flex justify-between items-center bg-white sticky top-0 z-10">
              <div>
                <h3 className="font-black uppercase text-sm tracking-widest">Manage Items</h3>
                <p className="text-[10px] font-bold text-slate-400 uppercase mt-1">Franchise: {selectedGroup.franchise_id}</p>
              </div>
              <button onClick={() => { setSelectedGroup(null); setSelectedItemIds([]); }} className="p-2 hover:bg-slate-100 rounded-full transition-colors"><FiX size={20} /></button>
            </div>

            <div className="p-6 overflow-y-auto custom-scrollbar space-y-2">
              {selectedGroup.displayItems.map((item) => (
                <div key={item.id} className={`flex items-center justify-between p-4 rounded-2xl border-2 transition-all ${selectedItemIds.includes(item.id) ? 'border-black bg-slate-50' : 'border-transparent bg-slate-50'}`}>
                  <label className="flex items-center gap-4 cursor-pointer flex-1 min-w-0">
                    <input
                      type="checkbox"
                      disabled={item.status === 'fulfilled'}
                      checked={selectedItemIds.includes(item.id)}
                      onChange={() => toggleItemSelection(item.id)}
                      className="w-5 h-5 rounded border-2 border-slate-300 checked:bg-black accent-black cursor-pointer disabled:opacity-20 shrink-0 transition-all"
                    />
                    <span className={`text-xs font-black uppercase truncate ${item.status === 'fulfilled' ? 'text-slate-300 line-through' : 'text-black'}`}>
                      {item.name}
                    </span>
                  </label>
                  {item.status === 'fulfilled' && (
                    <button
                      onClick={() => updateItemStatus([item.id], 'pending')}
                      className="text-rose-600 hover:bg-rose-50 p-2 rounded-lg transition-all"
                      title="Undo Fulfillment"
                    >
                      <RotateCcw size={16} />
                    </button>
                  )}
                </div>
              ))}
            </div>

            <div className="p-6 bg-slate-50 border-t-2 border-slate-100 pb-10 sm:pb-6">
              <button
                onClick={() => updateItemStatus(selectedItemIds, 'fulfilled')}
                disabled={selectedItemIds.length === 0}
                className="w-full py-4 bg-black text-white rounded-2xl font-black uppercase text-[10px] tracking-[0.2em] shadow-lg shadow-black/20 active:scale-95 transition-all disabled:opacity-30 disabled:scale-100"
              >
                Mark Selected as Fulfilled
              </button>
            </div>
          </div>
        </div>
      )}

      {/* HEADER */}
      <div className="sticky top-0 z-30 bg-white border-b border-slate-200 px-4 md:px-8 py-4 flex flex-col md:flex-row md:items-center justify-between shadow-sm gap-4">
        <div className="flex items-center justify-between w-full md:w-auto">
          <button onClick={() => navigate(-1)} className="flex items-center gap-2 text-black font-black uppercase text-xs tracking-widest hover:text-black/70 transition-colors">
            <ArrowLeft size={18} /> <span>Back</span>
          </button>
          <h1 className="text-base md:text-xl font-black uppercase tracking-widest text-center md:hidden text-black">Stock Requests</h1>
          <div className="flex items-center gap-2 md:hidden">
            <div className="bg-slate-100 border border-slate-200 rounded-md px-3 py-1.5 flex items-center gap-2">
              <span className="text-[10px] font-black text-slate-700 uppercase tracking-wide">ID:</span>
              <span className="text-[10px] font-black text-slate-900 uppercase tracking-wide">{profile?.franchise_id || "CENTRAL"}</span>
            </div>
          </div>
        </div>
        <h1 className="text-xl font-black uppercase tracking-widest text-center hidden md:block absolute left-1/2 -translate-x-1/2 text-black">Stock <span style={{ color: BRAND_COLOR }}>Requests</span></h1>
        <div className="hidden md:flex items-center gap-3">
          <div className="bg-slate-100 border border-slate-200 rounded-md px-3 py-1.5 flex items-center gap-2">
            <span className="text-[11px] font-black text-slate-700 uppercase tracking-wide">ID :</span>
            <span className="text-[11px] font-black text-slate-900 uppercase tracking-wide">{profile?.franchise_id || "CENTRAL"}</span>
          </div>
        </div>
      </div>

      <div className="max-w-[1400px] mx-auto px-4 md:px-8 mt-6 md:mt-8">

        {/* ---- UPDATED TOOLBAR (GRID LAYOUT) ---- */}
        <div className="flex flex-col lg:flex-row items-center gap-4 mb-8">

          {/* 1. Search Bar (Flex Grow) */}
          <div className="flex items-center gap-3 bg-white rounded-2xl px-4 h-12 md:h-14 border-2 border-slate-200 hover:border-black transition-colors w-full lg:flex-1">
            <Search size={18} className="text-black shrink-0" />
            <input
              placeholder="SEARCH BY ITEM OR FRANCHISE..."
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              className="bg-transparent border-none outline-none text-[10px] md:text-xs font-black w-full placeholder:text-slate-300 text-black uppercase"
            />
          </div>

          {/* 2. Controls Grid */}
          <div className="flex flex-wrap items-center gap-3 w-full lg:w-auto">

            {/* A. Date Toggle */}
            <div className="bg-slate-100 p-1 rounded-2xl flex shrink-0 h-12 md:h-14 items-center w-full sm:w-auto">
              <button
                onClick={() => setIsRange(false)}
                className={`flex-1 sm:flex-none px-4 h-full rounded-xl text-[9px] font-black uppercase transition-all ${!isRange ? "bg-white shadow-sm text-black" : "text-slate-400 hover:text-slate-600"}`}
              >
                Single
              </button>
              <button
                onClick={() => setIsRange(true)}
                className={`flex-1 sm:flex-none px-4 h-full rounded-xl text-[9px] font-black uppercase transition-all ${isRange ? "bg-white shadow-sm text-black" : "text-slate-400 hover:text-slate-600"}`}
              >
                Range
              </button>
            </div>

            {/* B. Date Inputs (Moved BEFORE Reset) */}
            <div className="flex items-center gap-2 h-12 md:h-14 bg-white border-2 border-slate-200 rounded-2xl px-4 flex-1 min-w-[200px] hover:border-black transition-colors">
              <Calendar size={18} className="text-black shrink-0" />
              {!isRange ? (
                <input
                  type="date"
                  value={singleDate}
                  onChange={(e) => setSingleDate(e.target.value)}
                  className="bg-transparent text-[10px] font-black outline-none cursor-pointer uppercase w-full text-center tracking-wider text-black"
                />
              ) : (
                <div className="flex items-center gap-1 w-full justify-center">
                  <input
                    type="date"
                    value={dateRange.start}
                    onChange={(e) => setDateRange({ ...dateRange, start: e.target.value })}
                    className="bg-transparent text-[9px] font-black outline-none w-full min-w-0 uppercase tracking-tighter text-black text-center"
                  />
                  <span className="text-[9px] font-black text-slate-300">-</span>
                  <input
                    type="date"
                    value={dateRange.end}
                    onChange={(e) => setDateRange({ ...dateRange, end: e.target.value })}
                    className="bg-transparent text-[9px] font-black outline-none w-full min-w-0 uppercase tracking-tighter text-black text-center"
                  />
                </div>
              )}
            </div>

            {/* C. Reset Button (Moved AFTER Date Inputs) */}
            <button
              onClick={resetFilters}
              className="h-12 md:h-14 w-12 md:w-14 flex items-center justify-center bg-slate-100 hover:bg-rose-50 text-slate-600 hover:text-rose-600 rounded-2xl border border-slate-200 transition-all active:scale-95 shrink-0"
              title="Reset Filters"
            >
              <RotateCcw size={18} className={loading ? "animate-spin" : ""} />
            </button>

          </div>
        </div>
        {/* ---- END TOOLBAR ---- */}

        {/* LOADING & EMPTY STATES */}
        {loading && requests.length === 0 ? (
          <div className="flex flex-col items-center justify-center py-20 text-slate-400 gap-4">
            <RotateCcw className="animate-spin" size={30} />
            <p className="text-[10px] font-black uppercase tracking-widest">Loading Requests...</p>
          </div>
        ) : filteredRequests.length === 0 ? (
          <div className="flex flex-col items-center justify-center py-20 text-slate-300 gap-4 border-2 border-dashed border-slate-200 rounded-[2.5rem] bg-white">
            <FiInbox size={40} />
            <p className="text-[10px] font-black uppercase tracking-widest">No Requests Found</p>
            <button onClick={resetFilters} className="text-black underline text-[10px] font-bold uppercase">Clear Filters</button>
          </div>
        ) : (
          <>
            {/* DESKTOP TABLE */}
            <div className="hidden lg:block border-2 border-slate-200 rounded-[2.5rem] overflow-hidden bg-white shadow-sm mb-10">
              <table className="w-full text-left border-separate border-spacing-0">
                <thead>
                  <tr style={{ backgroundColor: BRAND_COLOR }} className="text-white">
                    <th className="p-6 text-[10px] font-black uppercase tracking-widest w-20">S.No</th>
                    <th className="p-6 text-[10px] font-black uppercase tracking-widest">Company / Franchise</th>
                    <th className="p-6 text-[10px] font-black uppercase tracking-widest text-center">Items Requested</th>
                    <th className="p-6 text-[10px] font-black uppercase tracking-widest text-center">Date & Time</th>
