                                <div className="pt-4 border-t-2 border-slate-50 flex justify-between items-center">
                                    <div className="flex items-center gap-2 text-[10px] font-bold text-slate-400 uppercase"><Calendar size={12} /> {formatDateTime(inv.created_at)}</div>
                                    <span className="text-[10px] font-black uppercase text-slate-300 tracking-widest">View Details &rarr;</span>
                                </div>
                            </div>
                        ))}
                    </div>
                </div>
            </div>
        </div>
    );
}

export default CentralInvoices;

import React, { useEffect, useState, useMemo, useCallback } from "react";
import { useNavigate } from "react-router-dom";
import { supabase } from "../../supabase/supabaseClient";
import {
  ArrowLeft,
  Search,
  UserPlus,
  X,
  Calendar,
  Trash2,
  Edit2,
  Building2,
  ChevronDown,
  AlertTriangle,
  MapPin,
  User,
  Eye,
  EyeOff,
  Lock,
} from "lucide-react";
import { BRAND_GREEN } from "../../utils/theme";

// Consistency with your existing brand colors
const PRIMARY = BRAND_GREEN;
const ACTION_GREEN = BRAND_GREEN;
const DANGER_RED = "#dc2626";
const BORDER = "#e5e7eb";

function CentralProfiles() {
  const navigate = useNavigate();

  const [profiles, setProfiles] = useState([]);
  const [allCompanies, setAllCompanies] = useState([]);
  const [loading, setLoading] = useState(true);
  const [searchQuery, setSearchQuery] = useState("");
  const [companyFilter, setCompanyFilter] = useState("all");
  const [isMobile, setIsMobile] = useState(window.innerWidth < 1024);

  // Modal States
  const [showEditModal, setShowEditModal] = useState(false);
  const [showDeleteModal, setShowDeleteModal] = useState(false);
  const [selectedProfile, setSelectedProfile] = useState(null);
  const [profileToDelete, setProfileToDelete] = useState(null);

  const [editForm, setEditForm] = useState({});
  const [saving, setSaving] = useState(false);
  const [deleting, setDeleting] = useState(false);
  const [userFranchiseId, setUserFranchiseId] = useState("");

  // Password change states
  const [newPassword, setNewPassword] = useState("");
  const [confirmPassword, setConfirmPassword] = useState("");
  const [showNewPw, setShowNewPw] = useState(false);
  const [showConfirmPw, setShowConfirmPw] = useState(false);
  const [passwordMsg, setPasswordMsg] = useState("");
  const [changingPassword, setChangingPassword] = useState(false);

  useEffect(() => {
    const handleResize = () => setIsMobile(window.innerWidth < 1024);
    window.addEventListener('resize', handleResize);

    const init = async () => {
      const { data: { session } } = await supabase.auth.getSession();
      if (!session) return navigate("/");

      const [profileRes, listRes, companiesRes] = await Promise.all([
        supabase.from("profiles").select("role, franchise_id").eq("id", session.user.id).single(),
        supabase.from("profiles").select("*"),
        supabase.from("companies").select("company_name")
      ]);

      if (profileRes.data?.role !== "central") return navigate("/");

      setUserFranchiseId(profileRes.data?.franchise_id || "CENTRAL-HQ");
      setProfiles(listRes.data || []);

      if (companiesRes.data) {
        const names = companiesRes.data.map(c => c.company_name).filter(Boolean);
        setAllCompanies([...new Set(names)].sort());
      }

      setLoading(false);
    };
    init();

    return () => window.removeEventListener('resize', handleResize);
  }, [navigate]);

  const fetchProfiles = async () => {
    const { data } = await supabase.from("profiles").select("*");
    setProfiles(data || []);
  };

  const today = new Intl.DateTimeFormat('en-GB', {
    weekday: 'short',
    day: '2-digit',
    month: 'short',
    year: 'numeric'
  }).format(new Date());

  const dropdownCompanies = useMemo(() => {
    return ["all", ...allCompanies];
  }, [allCompanies]);

  const sortedAndFilteredProfiles = useMemo(() => {
    const query = searchQuery.toLowerCase();
    let filtered = profiles.filter(p => {
      const matchesSearch =
        p.name?.toLowerCase().includes(query) ||
        p.phone?.toLowerCase().includes(query) ||
        p.franchise_id?.toLowerCase().includes(query) ||
        p.address?.toLowerCase().includes(query);

      const matchesCompany = companyFilter === "all" || p.company === companyFilter;
      return matchesSearch && matchesCompany;
    });

    const roleOrder = { central: 1, stock: 2, franchise: 3 };
    return filtered.sort((a, b) => (roleOrder[a.role] || 4) - (roleOrder[b.role] || 4));
  }, [profiles, searchQuery, companyFilter]);

  const confirmDelete = (profile) => {
    setProfileToDelete(profile);
    setShowDeleteModal(true);
  };

  const handleDelete = async () => {
    if (!profileToDelete) return;
    setDeleting(true);
    const { error } = await supabase.from("profiles").delete().eq("id", profileToDelete.id);
    if (error) {
      alert("Error deleting user: " + error.message);
    } else {
      setProfiles(prev => prev.filter(p => p.id !== profileToDelete.id));
      setShowDeleteModal(false);
      setProfileToDelete(null);
    }
    setDeleting(false);
  };

  const openEditModal = (profile) => {
    setSelectedProfile(profile);
    setEditForm({ ...profile });
    setNewPassword("");
    setConfirmPassword("");
    setPasswordMsg("");
    setShowNewPw(false);
    setShowConfirmPw(false);
    setShowEditModal(true);
  };

  const handleInputChange = (e) => {
    setEditForm(prev => ({ ...prev, [e.target.name]: e.target.value }));
  };

  const saveChanges = async () => {
    setSaving(true);
    const { error } = await supabase.from("profiles").update(editForm).eq("id", selectedProfile.id);
    if (!error) {
      setShowEditModal(false);
      fetchProfiles();
    } else {
      alert("Update failed: " + error.message);
    }
    setSaving(false);
  };

  const handlePasswordChange = async () => {
    setPasswordMsg("");
    if (!newPassword || !confirmPassword) {
      setPasswordMsg("Please fill both password fields");
      return;
    }
    if (newPassword.length < 6) {
      setPasswordMsg("Password must be at least 6 characters");
      return;
    }
    if (newPassword !== confirmPassword) {
      setPasswordMsg("Passwords do not match");
      return;
    }

    setChangingPassword(true);
    try {
      const { data, error } = await supabase.functions.invoke('update-password', {
        body: { userId: selectedProfile.id, newPassword }
      });

      if (error) {
        let msg = error.message || "Failed to update password";
        try {
          if (error.context) {
            const body = await error.context.json();
            if (body?.error) msg = body.error;
          }
        } catch (_) { }
        throw new Error(msg);
      }

      if (data?.error) throw new Error(data.error);

      setPasswordMsg("Password updated successfully!");
      setNewPassword("");
      setConfirmPassword("");
    } catch (err) {
      setPasswordMsg("Error: " + (err.message || "Failed to update password"));
    }
    setChangingPassword(false);
  };

  const getRoleStyle = (role) => {
    switch (role) {
      case 'central': return { background: '#dcfce7', color: '#166534', border: '1px solid #bbf7d0' };
      case 'stock': return { background: '#f3e8ff', color: '#6b21a8', border: '1px solid #e9d5ff' };
      case 'franchise': return { background: '#fef9c3', color: '#854d0e', border: '1px solid #fef08a' };
      default: return { background: '#f9fafb', color: '#6b7280', border: '1px solid #e5e7eb' };
    }
  };

  if (loading && profiles.length === 0) return <div style={styles.loader}>Loading Profiles...</div>;

  return (
    <div style={styles.page}>
      {/* HEADER */}
      <header style={styles.header}>
        <div style={styles.headerInner}>
          <button onClick={() => navigate(-1)} style={styles.backBtn}>
            <ArrowLeft size={18} /> <span>Back</span>
          </button>

          <h1 style={styles.heading}>
            User <span style={{ color: ACTION_GREEN }}>Profiles</span>
          </h1>

          <div style={styles.topRightActions}>
            <div style={styles.idBox}>
              ID : {userFranchiseId}
            </div>
          </div>
        </div>
      </header>

      <div style={{ ...styles.container, padding: isMobile ? "20px 15px" : "20px" }}>
        {/* SEARCH & DATE BAR */}
        <div style={{
          ...styles.actionBar,
          flexDirection: isMobile ? 'column' : 'row',
          gap: isMobile ? '12px' : '15px'
        }}>
          <div style={{ display: 'flex', flexDirection: isMobile ? 'column' : 'row', alignItems: isMobile ? 'stretch' : 'center', gap: '15px', width: '100%' }}>
            <div style={{ ...styles.searchWrapper, width: isMobile ? '100%' : '350px' }}>
              <Search size={18} color="#9ca3af" />
              <input
                style={styles.searchInput}
                placeholder="Search users..."
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
              />
            </div>

            {!isMobile && (
              <div style={styles.dateSection}>
                <Calendar size={16} color={PRIMARY} />
                <span style={styles.dateText}>{today}</span>
              </div>
            )}
          </div>
        </div>

        {/* FILTERS & ACTION ROW */}
        <div style={{
          ...styles.filterRow,
          marginBottom: isMobile ? '15px' : '25px',
          flexDirection: isMobile ? 'column' : 'row',
          justifyContent: 'space-between',
          alignItems: isMobile ? 'stretch' : 'center',
          gap: isMobile ? '15px' : '0'
        }}>
          {/* Left Side: Dropdown + Total Users Text */}
          <div style={{ display: 'flex', alignItems: 'center', gap: '15px', flexDirection: isMobile ? 'column' : 'row', width: isMobile ? '100%' : 'auto' }}>
            <div style={{ ...styles.companyFilterWrapper, width: isMobile ? '100%' : 'fit-content' }}>
              <Building2 size={16} color={PRIMARY} />
              <select
                style={{ ...styles.companySelect, flex: 1 }}
                value={companyFilter}
                onChange={(e) => setCompanyFilter(e.target.value)}
              >
                <option value="all">All Companies</option>
                {dropdownCompanies.filter(c => c !== "all").map(c => (
                  <option key={c} value={c}>{c}</option>
                ))}
              </select>
              <ChevronDown size={14} color="#6b7280" />
            </div>

            <span style={{
              fontSize: '11px',
              fontWeight: '800',
              color: '#000',
              letterSpacing: '0.5px',
              whiteSpace: 'nowrap',
              alignSelf: isMobile ? 'flex-start' : 'center',
              paddingLeft: isMobile ? '5px' : '0'
            }}>
              {sortedAndFilteredProfiles.length} TOTAL USERS
            </span>
          </div>

          {/* Register Button Right */}
          <button onClick={() => navigate("/register")} style={{
            ...styles.registerBtn,
            width: isMobile ? '100%' : 'auto',
            justifyContent: 'center',
            height: '42px'
          }}>
            <UserPlus size={16} />
            <span>REGISTER NEW USER</span>
          </button>
        </div>

        {/* CONTENT AREA: MOBILE CARDS OR DESKTOP TABLE */}
        {isMobile ? (
          <div style={{ display: 'flex', flexDirection: 'column', gap: '15px', paddingBottom: '40px' }}>
            {sortedAndFilteredProfiles.map((p) => (
              <div key={p.id} style={styles.mobileCard}>
                <div style={styles.cardHeader}>
                  <div style={{ display: 'flex', gap: '12px', alignItems: 'center' }}>
                    <div style={styles.avatar}>
                      <User size={20} />
                    </div>
                    <div>
                      <div style={styles.userName}>{p.name}</div>
                      <div style={styles.companyName}>{p.company || "No Company"}</div>
                    </div>
                  </div>
                  <span style={{ ...styles.roleBadge, ...getRoleStyle(p.role) }}>{p.role?.toUpperCase()}</span>
                </div>

                <div style={styles.gridInfo}>
                  <div>
                    <div style={styles.infoLabel}>Franchise ID</div>
                    <div style={{ fontSize: '13px', fontWeight: '800', color: PRIMARY }}>{p.franchise_id || "—"}</div>
                  </div>
                  <div>
                    <div style={styles.infoLabel}>Contact</div>
                    <div style={{ fontSize: '13px', fontWeight: '800', color: '#111827' }}>{p.phone || "—"}</div>
                  </div>
                </div>

                <div style={styles.addressBox}>
                  <MapPin style={{ flexShrink: 0 }} size={18} />
                  <span style={styles.addressText}>{p.address || "No Address Provided"}</span>
                </div>

                <div style={styles.cardActions}>
                  <button onClick={() => openEditModal(p)} style={styles.mobileActionBtnUpdate}>
                    <Edit2 size={14} /> UPDATE
                  </button>
                  <button onClick={() => confirmDelete(p)} style={styles.mobileActionBtnDelete}>
                    <Trash2 size={14} /> DELETE
                  </button>
                </div>
              </div>
            ))}
          </div>
        ) : (
          <div style={styles.tableWrapper}>
            <table style={styles.table}>
              <thead>
                <tr style={styles.thRow}>
                  <th style={styles.th}>S.NO</th>
                  <th style={styles.th}>USER</th>
                  <th style={styles.th}>COMPANY</th>
                  <th style={styles.th}>FRANCHISE ID</th>
                  <th style={styles.th}>ROLE</th>
                  <th style={styles.th}>CONTACT</th>
                  <th style={{ ...styles.th, textAlign: 'center' }}>ACTION</th>
                </tr>
              </thead>
              <tbody>
                {sortedAndFilteredProfiles.map((p, index) => (
                  <tr key={p.id} style={styles.tr}>
                    <td style={{ ...styles.td, color: '#9ca3af', fontWeight: 'bold' }}>{index + 1}</td>
                    <td style={styles.td}>{p.name}</td>
                    <td style={styles.td}>{p.company || "—"}</td>
                    <td style={styles.td}><code style={styles.code}>{p.franchise_id || "—"}</code></td>
                    <td style={styles.td}>
                      <span style={{ ...styles.roleBadge, ...getRoleStyle(p.role) }}>
                        {p.role?.toUpperCase()}
                      </span>
                    </td>
                    <td style={styles.td}>{p.phone || "—"}</td>
                    <td style={{ ...styles.td, textAlign: 'center' }}>
                      <div style={{ display: 'flex', gap: '12px', justifyContent: 'center' }}>
                        <button onClick={() => openEditModal(p)} style={styles.actionIconBtn}>
                          <Edit2 size={16} color={ACTION_GREEN} />
                        </button>
                        <button onClick={() => confirmDelete(p)} style={styles.actionIconBtn}>
                          <Trash2 size={16} color={DANGER_RED} />
                        </button>
                      </div>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </div>

      {/* EDIT MODAL */}
      {showEditModal && (
        <div style={styles.modalOverlay} onClick={() => setShowEditModal(false)}>
          <div style={{
            ...styles.modal,
            width: isMobile ? '95%' : '650px', // slightly wider to fit new fields cleanly
            maxHeight: '90vh',
            overflowY: 'auto'
          }} onClick={e => e.stopPropagation()}>
            <div style={styles.modalHeader}>
              <h3 style={{ margin: 0, fontSize: isMobile ? '18px' : '20px' }}>Update Profile</h3>
              <button onClick={() => setShowEditModal(false)} style={styles.closeBtn}><X size={20} /></button>
            </div>
            <div style={styles.modalBody}>
              <div style={{ ...styles.formRow, flexDirection: isMobile ? 'column' : 'row' }}>
                <div style={styles.inputGroup}>
                  <label style={styles.label}>Full Name</label>
                  <input style={styles.modalInput} name="name" value={editForm.name || ""} onChange={handleInputChange} />
                </div>

                <div style={styles.inputGroup}>
                  <label style={styles.label}>Work Email</label>
                  <input style={styles.modalInput} name="email" value={editForm.email || ""} onChange={handleInputChange} />
                </div>
              </div>

              <div style={{ ...styles.formRow, flexDirection: isMobile ? 'column' : 'row' }}>
                <div style={styles.inputGroup}>
                  <label style={styles.label}>Phone Number</label>
                  <input style={styles.modalInput} name="phone" value={editForm.phone || ""} onChange={handleInputChange} />
                </div>

                <div style={styles.inputGroup}>
                  <label style={styles.label}>System Role</label>
                  <div style={styles.selectWrapper}>
                    <select style={styles.modalSelect} name="role" value={editForm.role || ""} onChange={handleInputChange}>
                      <option value="central">Central</option>
                      <option value="franchise">Franchise</option>
                      <option value="stock">Stock Manager</option>
                    </select>
                    <ChevronDown size={18} color="#9ca3af" style={styles.selectIcon} />
                  </div>
                </div>
              </div>

              <div style={{ ...styles.formRow, flexDirection: isMobile ? 'column' : 'row' }}>
                <div style={styles.inputGroup}>
                  <label style={styles.label}>Company Name</label>
                  <div style={styles.selectWrapper}>
                    <select
                      style={styles.modalSelect}
                      name="company"
                      value={editForm.company || ""}
                      onChange={handleInputChange}
                    >
                      <option value="">Select Company</option>
                      {allCompanies.map(c => (
                        <option key={c} value={c}>{c}</option>
                      ))}
                    </select>
                    <ChevronDown size={18} color="#9ca3af" style={styles.selectIcon} />
                  </div>
                </div>
                <div style={styles.inputGroup}>
                  <label style={styles.label}>Franchise ID</label>
                  <input style={styles.modalInput} name="franchise_id" value={editForm.franchise_id || ""} onChange={handleInputChange} />
                </div>
              </div>

              {/* NEW FIELDS ADDED HERE */}
              <div style={{ ...styles.formRow, flexDirection: isMobile ? 'column' : 'row' }}>
                <div style={styles.inputGroup}>
                  <label style={styles.label}>Branch Location</label>
                  <input style={styles.modalInput} name="branch_location" value={editForm.branch_location || ""} onChange={handleInputChange} />
                </div>
                <div style={styles.inputGroup}>
                  <label style={styles.label}>Nearest Bus Stop</label>
                  <input style={styles.modalInput} name="nearest_bus_stop" value={editForm.nearest_bus_stop || ""} onChange={handleInputChange} />
                </div>
              </div>

              <div style={{ ...styles.formRow, flexDirection: isMobile ? 'column' : 'row' }}>
                <div style={styles.inputGroup}>
                  <label style={styles.label}>City</label>
                  <input style={styles.modalInput} name="city" value={editForm.city || ""} onChange={handleInputChange} />
                </div>
                <div style={styles.inputGroup}>
                  <label style={styles.label}>State</label>
                  <input style={styles.modalInput} name="state" value={editForm.state || ""} onChange={handleInputChange} />
                </div>
              </div>

              <div style={{ ...styles.formRow, flexDirection: isMobile ? 'column' : 'row' }}>
                <div style={styles.inputGroup}>
                  <label style={styles.label}>Country</label>
                  <input style={styles.modalInput} name="country" value={editForm.country || "India"} onChange={handleInputChange} />
                </div>
                <div style={styles.inputGroup}>
                  <label style={styles.label}>Pincode</label>
                  <input style={styles.modalInput} name="pincode" value={editForm.pincode || ""} onChange={handleInputChange} />
                </div>
              </div>
              {/* END OF NEW FIELDS */}

              <div style={styles.inputGroup}>
                <label style={styles.label}>Permanent Address</label>
                <textarea
                  style={{ ...styles.modalInput, height: '80px', resize: 'none' }}
                  name="address"
                  value={editForm.address || ""}
                  onChange={handleInputChange}
                />
              </div>

              <button onClick={saveChanges} disabled={saving} style={styles.saveBtn}>
                {saving ? "SAVING..." : "SAVE CHANGES"}
              </button>

              {/* CHANGE PASSWORD SECTION */}
              <div style={{ marginTop: '15px', paddingTop: '20px', borderTop: `1px solid ${BORDER}` }}>
                <span style={{ fontSize: '12px', fontWeight: '900', color: '#111827', textTransform: 'uppercase', letterSpacing: '0.5px', display: 'block', marginBottom: '12px' }}>
                  Change Password
                </span>

                <div style={{ marginBottom: '12px', padding: '12px 14px', background: '#f1f5f9', borderRadius: '12px', border: `1px solid ${BORDER}` }}>
                  <span style={{ fontSize: '10px', fontWeight: '800', color: '#9ca3af', textTransform: 'uppercase', letterSpacing: '0.5px' }}>Email</span>
                  <p style={{ margin: '4px 0 0', fontSize: '13px', fontWeight: '700', color: '#374151' }}>{selectedProfile?.email || 'N/A'}</p>
                </div>

                <div style={{ ...styles.formRow, flexDirection: isMobile ? 'column' : 'row' }}>
                  <div style={styles.inputGroup}>
                    <label style={styles.label}>New Password</label>
                    <div style={{ position: 'relative' }}>
                      <input
                        style={{ ...styles.modalInput, width: '100%', boxSizing: 'border-box', paddingRight: '44px' }}
                        type={showNewPw ? 'text' : 'password'}
                        placeholder="Min 6 characters"
                        value={newPassword}
                        onChange={(e) => setNewPassword(e.target.value)}
                      />
                      <button onClick={() => setShowNewPw(!showNewPw)} style={{ position: 'absolute', right: '12px', top: '50%', transform: 'translateY(-50%)', background: 'none', border: 'none', cursor: 'pointer', color: '#9ca3af' }}>
                        {showNewPw ? <EyeOff size={16} /> : <Eye size={16} />}
                      </button>
                    </div>
                  </div>
                  <div style={styles.inputGroup}>
                    <label style={styles.label}>Confirm Password</label>
                    <div style={{ position: 'relative' }}>
                      <input
                        style={{ ...styles.modalInput, width: '100%', boxSizing: 'border-box', paddingRight: '44px' }}
                        type={showConfirmPw ? 'text' : 'password'}
                        placeholder="Re-enter password"
                        value={confirmPassword}
                        onChange={(e) => setConfirmPassword(e.target.value)}
                      />
                      <button onClick={() => setShowConfirmPw(!showConfirmPw)} style={{ position: 'absolute', right: '12px', top: '50%', transform: 'translateY(-50%)', background: 'none', border: 'none', cursor: 'pointer', color: '#9ca3af' }}>
                        {showConfirmPw ? <EyeOff size={16} /> : <Eye size={16} />}
                      </button>
                    </div>
                  </div>
                </div>

                {passwordMsg && (
                  <p style={{ fontSize: '11px', fontWeight: '800', textAlign: 'center', marginTop: '8px', color: passwordMsg.includes('success') ? ACTION_GREEN : '#dc2626' }}>
                    {passwordMsg}
                  </p>
                )}

                <button
                  onClick={handlePasswordChange}
                  disabled={changingPassword || !newPassword || !confirmPassword}
                  style={{ ...styles.saveBtn, background: '#1e293b', width: '100%', opacity: (!newPassword || !confirmPassword) ? 0.5 : 1 }}
                >
                  {changingPassword ? "UPDATING..." : "UPDATE PASSWORD"}
                </button>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* DELETE CONFIRMATION MODAL */}
      {showDeleteModal && (
        <div style={styles.modalOverlay} onClick={() => setShowDeleteModal(false)}>
          <div style={{ ...styles.modal, width: isMobile ? '90%' : '400px', textAlign: 'center' }} onClick={e => e.stopPropagation()}>
            <div style={{ color: DANGER_RED, marginBottom: '20px' }}>
              <AlertTriangle size={48} style={{ margin: '0 auto' }} />
            </div>
            <h3 style={{ margin: '0 0 10px 0', fontSize: isMobile ? '16px' : '18px' }}>Confirm Deletion</h3>
            <p style={{ color: '#6b7280', fontSize: '13px', lineHeight: '1.5', marginBottom: '25px' }}>
              Are you sure you want to delete <strong>{profileToDelete?.name}</strong>?<br />
              This action cannot be undone.
            </p>
            <div style={{ display: 'flex', gap: '12px' }}>
              <button
                onClick={() => setShowDeleteModal(false)}
                style={{ ...styles.saveBtn, background: '#f3f4f6', color: '#374151', flex: 1, marginTop: 0 }}
              >
                CANCEL
              </button>
              <button
                onClick={handleDelete}
                disabled={deleting}
                style={{ ...styles.saveBtn, background: DANGER_RED, flex: 1, marginTop: 0 }}
              >
                {deleting ? "..." : "DELETE"}
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

const styles = {
  page: { background: "#fff", minHeight: "100vh", fontFamily: '"Inter", sans-serif', color: "#111827" },
  container: { maxWidth: "1400px", margin: "0 auto" },

  header: { background: '#fff', borderBottom: '1px solid #e2e8f0', position: 'relative', zIndex: 30, width: '100%', marginBottom: '24px', boxShadow: '0 1px 2px 0 rgba(0, 0, 0, 0.05)' },
  headerInner: { padding: '16px 24px', display: 'flex', alignItems: 'center', justifyContent: 'space-between', width: '100%', gap: '12px' },
  backBtn: { background: "none", border: "none", color: "#000", fontSize: "14px", fontWeight: "700", cursor: "pointer", padding: 0, display: 'flex', alignItems: 'center', gap: '6px', flexShrink: 0 },
  heading: { fontWeight: "900", color: "#000", textTransform: 'uppercase', letterSpacing: "-0.5px", margin: 0, fontSize: '20px', textAlign: 'center', flex: 1, lineHeight: 1.2 },
  topRightActions: { display: "flex", alignItems: "center", gap: "12px", flexShrink: 0 },
  idBox: { background: '#f1f5f9', border: '1px solid #e2e8f0', borderRadius: '6px', padding: '6px 12px', color: '#334155', fontSize: '11px', fontWeight: '900', textTransform: 'uppercase', letterSpacing: '0.5px', whiteSpace: 'nowrap' },

  registerBtn: { display: "flex", alignItems: "center", gap: "8px", background: ACTION_GREEN, color: "#fff", border: "none", padding: "8px 24px", borderRadius: "12px", fontSize: "12px", fontWeight: "800", cursor: "pointer", height: '46px' },

  actionBar: { display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: "15px" },
  filterRow: { display: "flex" },
  companyFilterWrapper: { display: "flex", alignItems: "center", gap: "10px", background: "#fff", border: `1.5px solid ${BORDER}`, padding: "8px 15px", borderRadius: "12px" },
  companySelect: { border: "none", background: "none", outline: "none", fontSize: "13px", fontWeight: "600", color: "#374151", cursor: "pointer", appearance: "none" },
  dateSection: { display: "flex", alignItems: "center", gap: "10px", background: "#f3f4f6", padding: "0 16px", borderRadius: "14px", border: `1px solid ${BORDER}`, height: "46px" },
  dateText: { fontSize: "12px", fontWeight: "700", color: "#4b5563", textTransform: "uppercase" },
  searchWrapper: { display: "flex", alignItems: "center", gap: "12px", background: "#f9fafb", border: `1.5px solid ${BORDER}`, borderRadius: "16px", padding: "0 16px", height: "46px" },
  searchInput: { border: "none", background: "none", padding: "14px 0", outline: "none", fontSize: "14px", width: "100%", fontWeight: "500" },
  tableWrapper: { border: `1px solid ${BORDER}`, borderRadius: "24px", overflow: "hidden" },
  table: { width: "100%", borderCollapse: "collapse", textAlign: "left" },
  thRow: { background: "#f3f4f6", borderBottom: `2px solid ${PRIMARY}` },
  th: { padding: "18px 24px", fontSize: "11px", fontWeight: "900", color: PRIMARY, letterSpacing: "1.5px" },
  tr: { borderTop: `1px solid ${BORDER}`, transition: "background-color 0.2s ease" },
  td: { padding: "16px 24px", fontSize: "13px", color: "#111827", fontWeight: "500" },
  code: { background: "#f3f4f6", padding: "2px 6px", borderRadius: "4px", fontSize: "11px", color: "#4b5563", fontFamily: "monospace" },
  roleBadge: { padding: "4px 12px", borderRadius: "20px", fontSize: "10px", fontWeight: "800", display: "inline-block" },
  actionIconBtn: { background: "none", border: "none", cursor: "pointer", display: "flex", alignItems: "center", justifyContent: "center", padding: "4px", borderRadius: "4px" },

  mobileCard: { background: '#fff', borderRadius: '24px', border: `1.5px solid ${BORDER}`, padding: '18px', boxShadow: '0 4px 12px rgba(0,0,0,0.03)' },
  cardHeader: { display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: '14px' },
  avatar: { width: '44px', height: '44px', borderRadius: '14px', background: '#f3f4f6', display: 'flex', alignItems: 'center', justifyContent: 'center', color: PRIMARY },
  userName: { fontWeight: '900', fontSize: '16px', color: '#111827' },
  companyName: { fontSize: '12px', color: '#9ca3af', fontWeight: '700' },
  gridInfo: { display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '12px', marginBottom: '16px', padding: '14px', background: '#f9fafb', borderRadius: '16px' },
  infoLabel: { fontSize: '10px', fontWeight: '800', color: '#9ca3af', textTransform: 'uppercase', marginBottom: '4px' },
  addressBox: { display: 'flex', alignItems: 'center', gap: '8px', marginBottom: '18px', color: '#6b7280' },
  addressText: { fontSize: '12px', fontWeight: '600', overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' },
  cardActions: { display: 'flex', gap: '12px', borderTop: `1px solid ${BORDER}`, paddingTop: '14px' },
  mobileActionBtnUpdate: { flex: 1, display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '8px', padding: '12px', borderRadius: '12px', background: '#f0fdf4', border: 'none', color: ACTION_GREEN, fontWeight: '800', fontSize: '11px' },
  mobileActionBtnDelete: { flex: 1, display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '8px', padding: '12px', borderRadius: '12px', background: '#fef2f2', border: 'none', color: DANGER_RED, fontWeight: '800', fontSize: '11px' },

  modalOverlay: { position: "fixed", inset: 0, background: "rgba(0,0,0,0.6)", display: "flex", alignItems: "center", justifyContent: "center", zIndex: 1000, backdropFilter: 'blur(6px)' },
  modal: { background: "#fff", borderRadius: "32px", padding: "25px", boxShadow: "0 25px 50px rgba(0,0,0,0.25)" },
  modalHeader: { display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: "25px" },
  modalBody: { display: "flex", flexDirection: "column", gap: "20px" },
  formRow: { display: 'flex', gap: '15px' },
  inputGroup: { display: "flex", flexDirection: "column", gap: "8px", flex: 1 },
  label: { fontSize: "11px", fontWeight: "800", color: "#9ca3af", textTransform: 'uppercase' },
  modalInput: { padding: "14px", borderRadius: "14px", border: `1.5px solid ${BORDER}`, outline: "none", fontSize: "14px", background: '#f9fafb' },

  selectWrapper: { position: 'relative', display: 'flex', alignItems: 'center', width: '100%' },
  modalSelect: {
    padding: "14px",
    paddingRight: "40px",
    borderRadius: "14px",
    border: `1.5px solid ${BORDER}`,
    outline: "none",
    fontSize: "14px",
    background: '#f9fafb',
    width: "100%",
    appearance: "none",
    cursor: "pointer",
    fontWeight: "500"
  },
  selectIcon: { position: 'absolute', right: '14px', pointerEvents: 'none' },

  saveBtn: { background: ACTION_GREEN, color: "#fff", border: "none", padding: "18px", borderRadius: "18px", fontWeight: "800", cursor: "pointer", marginTop: '10px', fontSize: '13px' },
  closeBtn: { background: "none", border: "none", color: "#9ca3af", cursor: "pointer" },
  loader: { height: "100vh", display: "flex", alignItems: "center", justifyContent: "center", fontWeight: "700", color: PRIMARY }
};

export default CentralProfiles;

import { useEffect, useState, useMemo } from "react";
import { supabase } from "../../supabase/supabaseClient";
import { devLog } from "../../utils/logger";
import { ArrowLeft } from "lucide-react";

const GREEN = "rgb(0,100,55)";
const LIGHT_GREEN = "rgba(0,100,55,0.05)";
const DANGER = "#e63946";
const CENTRAL_ID = "TV-1";

function PosManagement() {
  const [allCompanyRecords, setAllCompanyRecords] = useState([]);
  const [companies, setCompanies] = useState([]);
  const [selectedCompany, setSelectedCompany] = useState("");
  const [targetFranchise, setTargetFranchise] = useState("");
  const [deleteTargetId, setDeleteTargetId] = useState("");
  const [viewFranchise, setViewFranchise] = useState("");
  const [menus, setMenus] = useState([]);
  const [loading, setLoading] = useState(false);
  const [selectedCategory, setSelectedCategory] = useState("All");
  const [searchQuery, setSearchQuery] = useState("");
  const [myFranchiseId, setMyFranchiseId] = useState("");

  const [isMobile, setIsMobile] = useState(window.innerWidth < 768);
  const [toast, setToast] = useState({ show: false, message: "", type: "success" });
  const [isAddModalOpen, setIsAddModalOpen] = useState(false);
  const [isEditModalOpen, setIsEditModalOpen] = useState(false);
  const [newItem, setNewItem] = useState({ item_name: "", price: "", category: "" });
  const [editingItem, setEditingItem] = useState(null);

  useEffect(() => {
    const handleResize = () => setIsMobile(window.innerWidth < 768);
    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  const showToast = (message, type = "success") => {
    setToast({ show: true, message, type });
    setTimeout(() => setToast({ show: false, message: "", type: "success" }), 3500);
  };

  useEffect(() => {
    fetchFranchises();
    fetchCurrentUser();
  }, []);

  useEffect(() => {
    if (selectedCompany && viewFranchise) {
      const isValid = allCompanyRecords.some(
        p => p.company_name.toLowerCase() === selectedCompany.toLowerCase() && p.franchise_id === viewFranchise
      );
      if (!isValid) {
        setViewFranchise("");
        setMenus([]);
      }
    }
  }, [selectedCompany, allCompanyRecords, viewFranchise]);

  const fetchCurrentUser = async () => {
    try {
      const { data: { user }, error: userError } = await supabase.auth.getUser();
      if (userError) throw userError;

      if (user) {
        const { data, error } = await supabase.from("profiles").select("franchise_id").eq("id", user.id).single();
        if (error) throw error;
        if (data) setMyFranchiseId(data.franchise_id);
      }
    } catch (err) {
      console.error("Error fetching user:", err.message);
    }
  };

  const fetchFranchises = async () => {
    try {
      // 1. Fetch company names from the companies table
      const { data: companyData, error: companyError } = await supabase
        .from("companies")
        .select("company_name");

      if (companyError) throw companyError;

      if (companyData) {
        const uniqueCompanies = [...new Set(
          companyData
            .map(c => c.company_name?.trim())
            .filter(Boolean)
        )].sort();
        devLog("=== DEBUG 1: Companies from companies table ===", uniqueCompanies);
        setCompanies(uniqueCompanies);
      }

      // 2. Fetch franchise IDs from the profiles table
      const { data: profileData, error: profileError } = await supabase
        .from("profiles")
        .select("franchise_id, company");

      if (profileError) throw profileError;

      if (profileData) {
        devLog("=== DEBUG 2: Raw profiles data ===", profileData);

        const cleanedData = profileData
          .filter(d => d.company && String(d.company).trim() !== "")
          .map(d => ({
            company_name: String(d.company).trim(),
            franchise_id: d.franchise_id ? String(d.franchise_id).trim() : null
          }));

        devLog("=== DEBUG 3: Cleaned allCompanyRecords ===", cleanedData);
        setAllCompanyRecords(cleanedData);
      }
    } catch (err) {
      showToast("Failed to load data: " + err.message, "error");
    }
  };

  // DEBUGGING ADDED TO THE MEMO FILTER
  const filteredFranchises = useMemo(() => {
    devLog("=== DEBUG 3: Re-running filteredFranchises calculation ===");
    devLog("Selected Company State:", `"${selectedCompany}"`);

    if (!selectedCompany) {
      devLog("Result: No company selected, returning empty array.");
      return [];
    }

    const filteredRecords = allCompanyRecords.filter(p => {
      const nameMatches = p.company_name.toLowerCase() === selectedCompany.toLowerCase();
      const hasValidId = p.franchise_id !== null && p.franchise_id !== "";

      // If it has an ID but the name fails to match, let's log it to see why
      if (hasValidId && p.company_name.toLowerCase().includes(selectedCompany.toLowerCase().substring(0, 3))) {
        devLog(`Checking record: DB Name="${p.company_name}", Selected="${selectedCompany}", Match=${nameMatches}`);
      }

      return nameMatches && hasValidId;
    });

    devLog("Filtered Records Matching Company:", filteredRecords);

    const matchingIds = filteredRecords.map(p => p.franchise_id);
    const finalIds = [...new Set(matchingIds)].sort();

    devLog("Final Unique IDs mapped to dropdown:", finalIds);
    return finalIds;
  }, [selectedCompany, allCompanyRecords]);

  const getMenu = async (idOverride) => {
    const id = (idOverride || viewFranchise)?.toString().trim();
    if (!id) { setMenus([]); return; }

    setLoading(true);
    setMenus([]);

    try {
      const cacheKey = `pos_menu_${id}`;
      const cachedMenu = sessionStorage.getItem(cacheKey);

      if (cachedMenu) {
        setMenus(JSON.parse(cachedMenu));
        setSelectedCategory("All");
        setLoading(false);
        return;
      }

      const { data, error } = await supabase.from("menus").select("*").eq("franchise_id", id).order("category");
      if (error) throw error;

      const fetchedMenu = data || [];
      setMenus(fetchedMenu);
      sessionStorage.setItem(cacheKey, JSON.stringify(fetchedMenu));

    } catch (err) {
      showToast("Failed to load menu: " + err.message, "error");
    } finally {
      setSelectedCategory("All");
      setLoading(false);
    }
  };

  const refreshMenuCache = (id) => {
    sessionStorage.removeItem(`pos_menu_${id}`);
    getMenu(id);
  };

  const cloneFromCentral = async () => {
    const finalTargetId = targetFranchise.trim();
    if (!finalTargetId) return showToast("Enter Target ID", "error");

    const exists = allCompanyRecords.some(p => p.franchise_id === finalTargetId);
    if (!exists) return showToast(`ID ${finalTargetId} not found in database`, "error");

    setLoading(true);
    try {
      const { error } = await supabase.rpc('clone_franchise_menu', {
        target_id: finalTargetId,
        central_id: CENTRAL_ID
      });

      if (error) throw error;

      showToast(`🚀 Menu Synced to ${finalTargetId}`);
      refreshMenuCache(finalTargetId);
      setTargetFranchise("");
    } catch (err) {
      showToast(err.message, "error");
    } finally {
      setLoading(false);
    }
  };

  const deleteWholeMenu = async () => {
    const finalTargetId = deleteTargetId.trim();
    if (!finalTargetId) return showToast("Enter Franchise ID", "error");
    if (finalTargetId === CENTRAL_ID) return showToast("Cannot wipe Central", "error");

    const exists = allCompanyRecords.some(p => p.franchise_id === finalTargetId);
    if (!exists) return showToast(`Franchise ID ${finalTargetId} not found in database`, "error");

    if (window.confirm(`⚠️ DANGER: Permanent wipe for ${finalTargetId}?`)) {
      setLoading(true);
      try {
        const { error } = await supabase.rpc('delete_franchise_menu_global', {
          target_id: finalTargetId
        });

        if (error) throw error;

        showToast(`🗑️ Menu Wiped for ${finalTargetId}`, "success");
        sessionStorage.removeItem(`pos_menu_${finalTargetId}`);
        if (viewFranchise === finalTargetId) setMenus([]);
        setDeleteTargetId("");
      } catch (err) {
        showToast(err.message, "error");
      } finally {
        setLoading(false);
      }
    }
  };

  const deleteItem = async (id) => {
    if (!window.confirm("Are you sure you want to delete this item?")) return;
    try {
      const { error } = await supabase.from("menus").delete().eq("id", id);
      if (error) throw error;

      showToast("Item removed successfully");
      refreshMenuCache(viewFranchise);
    } catch (err) {
      showToast(err.message, "error");
    }
  };

  const addItem = async () => {
    const name = newItem.item_name.trim();
    const priceStr = newItem.price.toString().trim();
    const category = newItem.category.trim().toUpperCase();

    if (!name || !priceStr || !category) return showToast("Please fill all fields", "error");
    if (isNaN(Number(priceStr))) return showToast("Price must be a valid number", "error");

    setLoading(true);
    try {
      const { error } = await supabase.from("menus").insert({
        franchise_id: viewFranchise,
        item_name: name,
        price: Number(priceStr),
        category: category
      });

      if (error) throw error;

      showToast("Item added successfully");
      setIsAddModalOpen(false);
      setNewItem({ item_name: "", price: "", category: "" });
      refreshMenuCache(viewFranchise);
    } catch (err) {
      showToast(err.message, "error");
    } finally {
      setLoading(false);
    }
  };

  const saveEdit = async () => {
    const name = editingItem.item_name.toString().trim();
    const priceStr = editingItem.price.toString().trim();
    const category = editingItem.category.toString().trim().toUpperCase();

    if (!name || !priceStr || !category) return showToast("Fields cannot be empty", "error");
    if (isNaN(Number(priceStr))) return showToast("Price must be a valid number", "error");

    try {
      const { error } = await supabase.from("menus").update({
        item_name: name,
        price: Number(priceStr),
        category: category
      }).eq("id", editingItem.id);

      if (error) throw error;

      showToast("Item updated successfully");
      setIsEditModalOpen(false);
      refreshMenuCache(viewFranchise);
    } catch (err) {
      showToast(err.message, "error");
    }
  };

  const filteredMenus = menus.filter(m =>
    (selectedCategory === "All" || m.category === selectedCategory) &&
    m.item_name.toLowerCase().includes(searchQuery.toLowerCase())
  );

  const groupedMenu = filteredMenus.reduce((acc, i) => {
    acc[i.category] = acc[i.category] || [];
    acc[i.category].push(i);
    return acc;
  }, {});

  const categories = useMemo(() => ["All", ...new Set(menus.map(m => m.category))], [menus]);

  return (
    <div style={styles.page}>
      <style>{`
        * { box-sizing: border-box; } 
        body { margin: 0; padding: 0; }

        .category-scroll::-webkit-scrollbar { height: 6px; }
        .category-scroll::-webkit-scrollbar-track { background: transparent; }
        .category-scroll::-webkit-scrollbar-thumb { background-color: rgba(0, 0, 0, 0.2); border-radius: 10px; }
        .category-scroll::-webkit-scrollbar-thumb:hover { background-color: rgba(0, 0, 0, 0.4); }
      `}</style>

      {toast.show && (
        <div style={{ ...styles.toast, backgroundColor: toast.type === "success" ? GREEN : DANGER }}>
          {toast.message}
        </div>
      )}

      {/* HEADER */}
      <header style={styles.header}>
        <div style={styles.headerInner}>
          <button onClick={() => window.history.back()} style={styles.backBtn}>
            <ArrowLeft size={18} /> <span>Back</span>
          </button>
          <h1 style={styles.heading}>
            Menu <span style={{ color: GREEN }}>Management</span>
          </h1>
          <div style={styles.idBox}>
            ID : {myFranchiseId || "---"}
          </div>
        </div>
      </header>

      <main style={styles.mainContent}>

        {/* =========================================
            SECTION 1: COMPANY & FRANCHISE SELECTION 
            ========================================= */}
        <section style={styles.controlCard}>
          <div style={{ ...styles.row, flexDirection: isMobile ? 'column' : 'row', marginBottom: 0 }}>
            <div style={{ ...styles.selectWrapper, width: isMobile ? '100%' : '50%' }}>
              <label style={styles.miniLabel}>Select a Company</label>
              <select
                style={styles.premiumSelect}
                value={selectedCompany}
                onChange={e => {
                  devLog("=== DEBUG 0: Dropdown Change Triggered ===", `"${e.target.value}"`);
                  setSelectedCompany(e.target.value);
                  setViewFranchise("");
                  setMenus([]);
                }}
              >
                <option value="">-- View All Companies --</option>
                {companies.map(c => <option key={c} value={c}>{c}</option>)}
              </select>
            </div>

            <div style={{ ...styles.selectWrapper, width: isMobile ? '100%' : '50%' }}>
              <label style={styles.miniLabel}>Select Franchise ID</label>
              <select
                style={{ ...styles.premiumSelect, opacity: !selectedCompany ? 0.5 : 1 }}
                disabled={!selectedCompany}
                value={viewFranchise}
                onChange={e => {
                  const val = e.target.value;
                  setViewFranchise(val);
                  getMenu(val);
                }}
              >
                <option value="">
                  {!selectedCompany
                    ? "Select a Company First"
                    : (filteredFranchises.length === 0 ? "No IDs assigned to this company" : "-- Choose Franchise --")}
                </option>
                {filteredFranchises.map(id => <option key={id} value={id}>{id}</option>)}
              </select>
            </div>
          </div>
        </section>

        {/* =========================================
            SECTION 2: ADMIN ACTIONS (SYNC & WIPE) 
            ========================================= */}
        <section style={{
          ...styles.adminCard,
          flexDirection: isMobile ? 'column' : 'row',
          alignItems: isMobile ? 'stretch' : 'center',
          justifyContent: isMobile ? 'flex-start' : 'space-between'
        }}>
          {/* Sync Block */}
          <div style={{ ...styles.inputGroup, width: isMobile ? '100%' : 'auto' }}>
            <button onClick={cloneFromCentral} style={{ ...styles.primaryBtn, width: isMobile ? '100%' : 'auto' }} disabled={loading}>
              Sync from Central
            </button>
            <input
              style={{ ...styles.premiumInput, width: isMobile ? '100%' : '160px' }}
              placeholder="Target ID"
              value={targetFranchise}
              onChange={e => setTargetFranchise(e.target.value)}
            />
          </div>

          {isMobile && <div style={{ height: '1px', background: '#eee', margin: '8px 0' }}></div>}

          {/* Wipe Block */}
          <div style={{ ...styles.inputGroup, width: isMobile ? '100%' : 'auto' }}>
            <input
              style={{ ...styles.premiumInput, borderColor: DANGER, width: isMobile ? '100%' : '160px' }}
              placeholder="Wipe ID"
              value={deleteTargetId}
              onChange={e => setDeleteTargetId(e.target.value)}
            />
            <button onClick={deleteWholeMenu} style={{ ...styles.dangerBtn, width: isMobile ? '100%' : 'auto' }} disabled={loading}>
              Wipe Menu
            </button>
          </div>
        </section>

        {/* =========================================
            SECTION 3: SEARCH & ADD ITEM
            ========================================= */}
        <section style={{ ...styles.controlCard, paddingBottom: '20px' }}>
          <div style={{ ...styles.searchRow, flexDirection: isMobile ? 'column' : 'row', margin: 0 }}>
            <div style={styles.searchBarWrapper}>
              <span style={styles.searchIcon}>🔍</span>
              <input
                style={styles.searchField}
                placeholder="Search items by name..."
                value={searchQuery}
                onChange={e => setSearchQuery(e.target.value)}
                disabled={!viewFranchise}
              />
            </div>
            <button
              onClick={() => setIsAddModalOpen(true)}
              style={{
                ...styles.addBtn,
                width: isMobile ? '100%' : 'auto',
                background: !viewFranchise ? '#f5f5f5' : GREEN,
                color: !viewFranchise ? '#aaa' : '#fff',
                cursor: !viewFranchise ? 'not-allowed' : 'pointer'
              }}
              disabled={!viewFranchise}
            >
              + Add Item
            </button>
          </div>
        </section>

        {/* =========================================
            SECTION 4: MENU ITEMS TABLE & CATEGORIES
            ========================================= */}
        <section style={{ ...styles.controlCard, minHeight: '300px' }}>

          {/* Categories Tab Header */}
          {menus.length > 0 && (
            <div style={{ borderBottom: '1px solid #edf2f7', paddingBottom: '16px', marginBottom: '16px' }}>
              <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '12px' }}>
                <h2 style={{ fontSize: '16px', margin: 0, fontWeight: '800', color: '#334155' }}>Menu Categories</h2>
                <span style={styles.totalBadge}>Total Items: {filteredMenus.length}</span>
              </div>
              <div style={styles.scrollWrapper} className="category-scroll">
                {categories.map(c => (
                  <button key={c} onClick={() => setSelectedCategory(c)} style={selectedCategory === c ? styles.activeTab : styles.tab}>
                    {c}
                  </button>
                ))}
              </div>
            </div>
          )}

          {/* Table / List Body */}
          <div style={styles.listContainer}>
            {loading ? (
              <div style={styles.loadingState}>Refreshing Menu...</div>
            ) : Object.keys(groupedMenu).length > 0 ? (
              Object.keys(groupedMenu).map(cat => (
                <div key={cat} style={styles.categoryGroup}>
                  <div style={styles.categoryHeaderContainer}>
                    <h3 style={styles.categoryHeader}>{cat}</h3>
                  </div>

                  <div style={styles.itemsWrapper}>
                    {groupedMenu[cat].map(item => (
                      <div key={item.id} style={styles.premiumItemRow}>
                        <div style={styles.itemLead}>
                          <div style={{ display: 'flex', flexDirection: 'column' }}>
                            <span style={styles.itemNameText}>{item.item_name}</span>
                            <span style={styles.itemPriceText}>₹{item.price}</span>
                          </div>
                        </div>
                        <div style={styles.itemActions}>
                          <button onClick={() => { setEditingItem(item); setIsEditModalOpen(true); }} style={styles.iconBtn}>Edit</button>
                          <button onClick={() => deleteItem(item.id)} style={styles.deleteBtn} title="Delete Item">
                            <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke={DANGER} strokeWidth="2">
                              <path d="M3 6h18M19 6v14a2 2 0 01-2 2H7a2 2 0 01-2-2V6m3 0V4a2 2 0 012-2h4a2 2 0 012 2v2" />
                            </svg>
                          </button>
                        </div>
                      </div>
                    ))}
                  </div>
                </div>
              ))
            ) : (
              <div style={styles.emptyState}>
                {viewFranchise
                  ? (searchQuery ? "No items match your search." : "No items found in this franchise menu. Click '+ Add Item' or Sync from Central.")
                  : "Please select a Company and Franchise to view the items table."}
              </div>
            )}
          </div>
        </section>

      </main>

      {/* =========================================
          MODALS
          ========================================= */}
      {isAddModalOpen && (
        <div style={styles.modalOverlay}>
          <div style={{ ...styles.modal, width: isMobile ? '90%' : '400px' }}>
            <h2 style={{ color: GREEN, marginBottom: '20px', fontSize: isMobile ? '20px' : '24px' }}>Add New Menu Item</h2>
            <label style={styles.label}>Item Name</label>
            <input style={styles.modalInput} placeholder="e.g. Chicken Burger" onChange={e => setNewItem({ ...newItem, item_name: e.target.value })} />
            <label style={styles.label}>Price (₹)</label>
            <input type="number" style={styles.modalInput} placeholder="e.g. 199" onChange={e => setNewItem({ ...newItem, price: e.target.value })} />
            <label style={styles.label}>Category</label>
            <input style={styles.modalInput} placeholder="e.g. BURGERS" onChange={e => setNewItem({ ...newItem, category: e.target.value })} />
            <div style={{ display: 'flex', gap: '12px', marginTop: '10px' }}>
              <button onClick={addItem} style={{ ...styles.primaryBtn, flex: 1 }} disabled={loading}>
                {loading ? "Saving..." : "Save Item"}
              </button>
              <button onClick={() => setIsAddModalOpen(false)} style={styles.cancelBtn} disabled={loading}>Cancel</button>
            </div>
          </div>
        </div>
      )}

      {isEditModalOpen && editingItem && (
        <div style={styles.modalOverlay}>
          <div style={{ ...styles.modal, width: isMobile ? '90%' : '400px' }}>
            <h2 style={{ color: GREEN, marginBottom: '20px', fontSize: isMobile ? '20px' : '24px' }}>Modify Item</h2>
            <label style={styles.label}>Item Name</label>
            <input style={styles.modalInput} value={editingItem.item_name} onChange={e => setEditingItem({ ...editingItem, item_name: e.target.value })} />
            <label style={styles.label}>Price (₹)</label>
            <input type="number" style={styles.modalInput} value={editingItem.price} onChange={e => setEditingItem({ ...editingItem, price: e.target.value })} />
            <label style={styles.label}>Category</label>
            <input style={styles.modalInput} value={editingItem.category} onChange={e => setEditingItem({ ...editingItem, category: e.target.value })} />
            <div style={{ display: 'flex', gap: '12px', marginTop: '10px' }}>
              <button onClick={saveEdit} style={{ ...styles.primaryBtn, flex: 1 }}>Update Item</button>
              <button onClick={() => setIsEditModalOpen(false)} style={styles.cancelBtn}>Cancel</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

