import { useState, useEffect } from "react";
import { supabase } from "../../supabase/supabaseClient";
import { useNavigate } from "react-router-dom";
import { useAuth } from "../../context/AuthContext";
import {
  ArrowLeft, Lock, LogOut, Eye, EyeOff,
  User, X, Check, Save, Hash, MapPin, Utensils, ShieldCheck
} from "lucide-react";

function FranchiseSettingsCard() {
  const navigate = useNavigate();
  const { logout, user: authUser } = useAuth();

  // --- STATES ---
  const [franchiseId, setFranchiseId] = useState("...");

  // Password Logic
  const [newPassword, setNewPassword] = useState("");
  const [confirmPassword, setConfirmPassword] = useState("");
  const [passwordMsg, setPasswordMsg] = useState("");
  const [loading, setLoading] = useState(false);
  const [showNew, setShowNew] = useState(false);
  const [showConfirm, setShowConfirm] = useState(false);

  // Modals
  const [showProfileModal, setShowProfileModal] = useState(false);
  const [showSecurityModal, setShowSecurityModal] = useState(false);

  // Profile Data
  const [profileData, setProfileData] = useState({
    name: "",
    email: "",
    phone: "",
    franchise_id: "",
    address: "",
    branch_location: "",
    company: "",
    pincode: "",
    state: "",
    city: "",
    country: "",
    nearest_bus_stop: ""
  });
  const [profileLoading, setProfileLoading] = useState(false);
  const [updateMsg, setUpdateMsg] = useState("");

  const brandGreen = "rgb(0, 100, 55)";

  const fetchProfile = async () => {
    if (!authUser?.id) return;
    try {
      const { data } = await supabase
        .from("profiles")
        .select("name, email, phone, franchise_id, address, branch_location, company, pincode, state, city, country, nearest_bus_stop")
        .eq("id", authUser.id)
        .single();

      if (data) {
        setProfileData({
          name: data.name || "",
          email: data.email || "",
          phone: data.phone || "",
          franchise_id: data.franchise_id || "",
          address: data.address || "",
          branch_location: data.branch_location || "",
          company: data.company || "",
          pincode: data.pincode || "",
          state: data.state || "",
          city: data.city || "",
          country: data.country || "",
          nearest_bus_stop: data.nearest_bus_stop || ""
        });
        setFranchiseId(data.franchise_id);
      }
    } catch (e) {
      console.error("Profile fetch error:", e);
    }
  };

  useEffect(() => {
    fetchProfile();
  }, [authUser]);

  const openProfile = async () => {
    setShowProfileModal(true);
    setProfileLoading(true);
    await fetchProfile();
    setProfileLoading(false);
  };

  const openSecurity = () => {
    setNewPassword("");
    setConfirmPassword("");
    setPasswordMsg("");
    setShowSecurityModal(true);
  };

  const handleUpdateProfile = async () => {
    setLoading(true);
    setUpdateMsg("");

    const { error } = await supabase
      .from("profiles")
      .update({
        phone: profileData.phone,
        address: profileData.address,
        branch_location: profileData.branch_location,
        pincode: profileData.pincode,
        city: profileData.city,
        nearest_bus_stop: profileData.nearest_bus_stop
      })
      .eq("id", authUser.id);

    if (error) {
      setUpdateMsg("Error: " + error.message);
    } else {
      setUpdateMsg("Profile updated successfully");
      setTimeout(() => {
        setShowProfileModal(false);
        setUpdateMsg("");
      }, 1500);
    }
    setLoading(false);
  };

  const handleChangePassword = async () => {
    setPasswordMsg("");
    if (!newPassword || !confirmPassword) {
      setPasswordMsg("Please fill all fields");
      return;
    }
    if (newPassword.length < 6) {
      setPasswordMsg("Min 6 characters required");
      return;
    }
    if (newPassword !== confirmPassword) {
      setPasswordMsg("Passwords do not match");
      return;
    }

    setLoading(true);
    const { error } = await supabase.auth.updateUser({ password: newPassword });
    setLoading(false);

    if (error) {
      setPasswordMsg("Error: " + error.message);
    } else {
      setPasswordMsg("Password updated successfully");
      setTimeout(() => setShowSecurityModal(false), 1500);
    }
  };

  const handleLogout = async () => {
    try {
      await supabase.auth.signOut();
      logout();
      navigate("/");
    } catch (err) {
      logout();
      navigate("/");
    }
  };

  return (
    <div className="min-h-screen bg-[#F8F9FA] text-slate-900 font-sans pb-20 relative">

      {/* --- STICKY HEADER --- */}
      <div className="sticky top-0 z-30 bg-white border-b border-slate-200 px-4 md:px-8 py-4 flex flex-col md:flex-row md:items-center justify-between shadow-sm gap-4 mb-8">
        <div className="flex items-center justify-between w-full md:w-auto">
          {/* Back Button */}
          <button onClick={() => navigate(-1)} className="flex items-center gap-2 text-black font-black uppercase text-xs tracking-widest hover:text-black/70 transition-colors">
            <ArrowLeft size={18} /> <span>Back</span>
          </button>

          {/* Mobile Title */}
          <h1 className="text-base md:text-xl font-black uppercase tracking-widest text-center md:hidden text-black">Settings</h1>

          {/* Mobile ID Box */}
          <div className="flex items-center gap-2 md:hidden">
            <div className="bg-slate-100 border border-slate-200 rounded-md px-3 py-1.5 flex items-center gap-2">
              <span className="text-[11px] font-black text-slate-700 uppercase tracking-wide">ID:</span>
              <span className="text-[11px] font-black text-slate-900 uppercase tracking-wide">{franchiseId}</span>
            </div>
          </div>
        </div>

        {/* Desktop Title */}
        <h1 className="text-xl font-black uppercase tracking-widest text-center hidden md:block absolute left-1/2 -translate-x-1/2 text-black">Settings</h1>

        {/* Desktop ID Box */}
        <div className="hidden md:flex items-center gap-3">
          <div className="bg-slate-100 border border-slate-200 rounded-md px-3 py-1.5 flex items-center gap-2">
            <span className="text-[11px] font-black text-slate-700 uppercase tracking-wide">ID :</span>
            <span className="text-[11px] font-black text-slate-900 uppercase tracking-wide">{franchiseId}</span>
          </div>
        </div>
      </div>

      <main className="max-w-[1000px] mx-auto px-4 md:px-8 pb-8 md:pb-12">

        {/* --- GRID LAYOUT --- */}
        <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 md:gap-6">

          {/* 1. IDENTITY CARD */}
          <button
            onClick={openProfile}
            className="bg-white rounded-[24px] md:rounded-[32px] border border-slate-200 p-8 shadow-sm flex flex-col justify-center items-center text-center transition-all hover:border-black/20 hover:-translate-y-1 hover:shadow-lg active:scale-95 group min-h-[260px]"
          >
            <div className="p-4 rounded-3xl bg-indigo-50 text-indigo-600 transition-all mb-6">
              <User size={36} strokeWidth={2.5} />
            </div>
            <h3 className="text-lg font-black text-black uppercase tracking-tight">Profile Details</h3>
            <p className="text-[10px] font-bold text-slate-400 mt-2 uppercase tracking-widest">Edit Personal Info</p>
          </button>

          {/* 2. MENU CARD */}
          <button
            onClick={() => navigate("/franchise/menu")}
            className="bg-white rounded-[24px] md:rounded-[32px] border border-slate-200 p-8 shadow-sm flex flex-col justify-center items-center text-center transition-all hover:border-black/20 hover:-translate-y-1 hover:shadow-lg active:scale-95 group min-h-[260px]"
          >
            <div className="p-4 rounded-3xl bg-emerald-50 text-emerald-600 transition-all mb-6">
              <Utensils size={36} strokeWidth={2.5} />
            </div>
            <h3 className="text-lg font-black text-black uppercase tracking-tight">Manage Menu</h3>
            <p className="text-[10px] font-bold text-slate-400 mt-2 uppercase tracking-widest">Update Items & Prices</p>
          </button>

          {/* 3. SECURITY CARD */}
          <button
            onClick={openSecurity}
            className="bg-white rounded-[24px] md:rounded-[32px] border border-slate-200 p-8 shadow-sm flex flex-col justify-center items-center text-center transition-all hover:border-black/20 hover:-translate-y-1 hover:shadow-lg active:scale-95 group min-h-[260px]"
          >
            <div className="p-4 rounded-3xl bg-slate-100 text-slate-600 transition-all mb-6">
              <ShieldCheck size={36} strokeWidth={2.5} />
            </div>
            <h3 className="text-lg font-black text-black uppercase tracking-tight">Security</h3>
            <p className="text-[10px] font-bold text-slate-400 mt-2 uppercase tracking-widest">Change Password</p>
          </button>

          {/* 4. LOGOUT CARD */}
          <button
            onClick={handleLogout}
            className="bg-white rounded-[24px] md:rounded-[32px] border p-8 shadow-sm flex flex-col justify-center items-center text-center transition-all hover:bg-rose-50 hover:-translate-y-1 hover:shadow-lg active:scale-95 group min-h-[260px]"
            style={{ borderColor: "rgba(225, 29, 72, 0.15)" }}
          >
            <div className="p-4 rounded-3xl bg-rose-50 text-rose-600 transition-all mb-6 group-hover:bg-rose-100">
              <LogOut size={36} strokeWidth={2.5} />
            </div>
            <h3 className="text-lg font-black text-black uppercase tracking-tight">Sign Out</h3>
            <p className="text-[10px] font-bold text-slate-400 mt-2 uppercase tracking-widest">End Session</p>
          </button>

        </div>
      </main>

      {/* --- 1. PROFILE MODAL --- */}
      {showProfileModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/40 backdrop-blur-sm overflow-y-auto">
          <div className="bg-white w-full max-w-lg rounded-[2.5rem] shadow-2xl overflow-hidden animate-in zoom-in duration-200 flex flex-col max-h-[90vh]">
            <div className="p-6 border-b border-slate-100 flex items-center justify-between shrink-0">
              <h2 className="text-lg font-black text-slate-900 uppercase tracking-tight">Edit Profile</h2>
              <button onClick={() => setShowProfileModal(false)} className="p-2 bg-slate-50 hover:bg-slate-100 rounded-full transition-colors">
                <X size={20} className="text-black" />
              </button>
            </div>
            <div className="p-6 overflow-y-auto custom-scrollbar">
              {profileLoading ? (
                <div className="py-20 text-center font-black text-slate-300 animate-pulse tracking-[0.2em] uppercase text-xs">Syncing profile...</div>
              ) : (
                <div className="space-y-6">
                  <div className="grid grid-cols-2 gap-3">
                    <div className="bg-slate-50 p-4 rounded-2xl border border-slate-100">
                      <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest flex items-center gap-1.5 mb-1"><Hash size={10} /> Franchise ID</label>
                      <p className="font-mono text-sm font-black text-slate-900">{profileData.franchise_id || "N/A"}</p>
                    </div>
                    <div className="bg-slate-50 p-4 rounded-2xl border border-slate-100">
                      <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest flex items-center gap-1.5 mb-1"><MapPin size={10} /> Company Name</label>
                      <p className="text-xs font-black text-slate-900 uppercase break-words leading-snug">{profileData.company || "N/A"}</p>
                    </div>
                  </div>
                  <div className="space-y-4">
                    <div className="relative space-y-1">
                      <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Store Address</label>
                      <input
                        type="text"
                        value={profileData.address}
                        onChange={(e) => setProfileData({ ...profileData, address: e.target.value })}
                        placeholder="Enter store address"
                        className="w-full py-3 px-4 rounded-xl bg-white border-2 border-slate-100 text-sm font-bold text-slate-900 focus:border-black outline-none transition-all"
                      />
                    </div>
                    <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                      <div className="relative space-y-1">
                        <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Owner Name (Uneditable)</label>
                        <input
                          type="text"
                          value={profileData.name}
                          disabled
                          className="w-full py-3 px-4 rounded-xl bg-slate-100 border-2 border-slate-100 text-sm font-bold text-slate-400 outline-none cursor-not-allowed"
                        />
                      </div>

                      <div className="relative space-y-1">
                        <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Email Address (Uneditable)</label>
                        <input
                          type="email"
                          value={profileData.email}
                          disabled
                          className="w-full py-3 px-4 rounded-xl bg-slate-100 border-2 border-slate-100 text-sm font-bold text-slate-400 outline-none cursor-not-allowed"
                        />
                      </div>

                      <div className="relative space-y-1">
                        <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Phone Number</label>
                        <input
                          type="text"
                          value={profileData.phone}
                          onChange={(e) => setProfileData({ ...profileData, phone: e.target.value })}
                          placeholder="Enter phone number"
                          className="w-full py-3 px-4 rounded-xl bg-white border-2 border-slate-100 text-sm font-bold text-slate-900 focus:border-black outline-none transition-all"
                        />
                      </div>
                    </div>

                    {/* REDUNDANT ADDRESS FIELD REMOVED FROM HERE */}

                    <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                      <div className="relative space-y-1">
                        <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Branch / Outlet Location</label>
                        <input
                          type="text"
                          value={profileData.branch_location}
                          onChange={(e) => setProfileData({ ...profileData, branch_location: e.target.value })}
                          placeholder="e.g. Main Branch, Outlet 2"
                          className="w-full py-3 px-4 rounded-xl bg-white border-2 border-slate-100 text-sm font-bold text-slate-900 focus:border-black outline-none transition-all"
                        />
                      </div>
                      <div className="relative space-y-1">
                        <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Nearest Bus Stop / Landmark</label>
                        <input
                          type="text"
                          value={profileData.nearest_bus_stop}
                          onChange={(e) => setProfileData({ ...profileData, nearest_bus_stop: e.target.value })}
                          placeholder="e.g. MG Road Bus Stop"
                          className="w-full py-3 px-4 rounded-xl bg-white border-2 border-slate-100 text-sm font-bold text-slate-900 focus:border-black outline-none transition-all"
                        />
                      </div>
                      <div className="relative space-y-1">
                        <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">City</label>
                        <input
                          type="text"
                          value={profileData.city}
                          onChange={(e) => setProfileData({ ...profileData, city: e.target.value })}
                          className="w-full py-3 px-4 rounded-xl bg-white border-2 border-slate-100 text-sm font-bold text-slate-900 focus:border-black outline-none transition-all"
                        />
                      </div>
                      <div className="relative space-y-1">
                        <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">State (Uneditable)</label>
                        <input
                          type="text"
                          value={profileData.state}
                          disabled
                          className="w-full py-3 px-4 rounded-xl bg-slate-100 border-2 border-slate-100 text-sm font-bold text-slate-400 outline-none cursor-not-allowed"
                        />
                      </div>
                      <div className="relative space-y-1">
                        <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Pincode</label>
                        <input
                          type="text"
                          value={profileData.pincode}
                          onChange={(e) => setProfileData({ ...profileData, pincode: e.target.value })}
                          className="w-full py-3 px-4 rounded-xl bg-white border-2 border-slate-100 text-sm font-bold text-slate-900 focus:border-black outline-none transition-all"
                        />
                      </div>
                      <div className="relative space-y-1">
                        <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Country (Uneditable)</label>
                        <input
                          type="text"
                          value={profileData.country}
                          disabled
                          className="w-full py-3 px-4 rounded-xl bg-slate-100 border-2 border-slate-100 text-sm font-bold text-slate-400 outline-none cursor-not-allowed"
                        />
                      </div>
                    </div>
                  </div>
                </div>
              )}
              {/* FIXED ALERTS: Red for errors, Green for success */}
              {updateMsg && (
                <div className={`mt-6 flex items-center gap-3 text-[10px] font-black uppercase tracking-widest p-4 rounded-xl border ${updateMsg.includes("Error") ? "bg-rose-50 text-rose-700 border-rose-100" : "bg-emerald-50 text-emerald-700 border-emerald-100"}`}>
                  {updateMsg.includes("Error") ? <X size={14} /> : <Check size={14} />} {updateMsg}
                </div>
              )}
            </div>
            <div className="p-6 border-t border-slate-100 bg-white shrink-0">
              <button onClick={handleUpdateProfile} disabled={loading || profileLoading} className="w-full text-white py-4 rounded-xl font-black text-xs uppercase tracking-[0.2em] flex items-center justify-center gap-2 transition-all hover:opacity-90 active:scale-95 disabled:opacity-50" style={{ backgroundColor: brandGreen }}>
                <Save size={16} /> Save Changes
              </button>
            </div>
          </div>
        </div>
      )}

      {/* --- 2. SECURITY MODAL --- */}
      {showSecurityModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/40 backdrop-blur-sm overflow-y-auto">
          <div className="bg-white w-full max-w-lg rounded-[2.5rem] shadow-2xl overflow-hidden animate-in zoom-in duration-200">
            <div className="p-6 border-b border-slate-100 flex items-center justify-between shrink-0">
              <h2 className="text-lg font-black text-slate-900 uppercase tracking-tight">Update Password</h2>
              <button onClick={() => setShowSecurityModal(false)} className="p-2 bg-slate-50 hover:bg-slate-100 rounded-full transition-colors">
                <X size={20} className="text-black" />
              </button>
            </div>

            <div className="p-8">
              <div className="space-y-5">
                <div className="relative">
                  <input
                    type={showNew ? "text" : "password"}
                    placeholder="New Password"
                    value={newPassword}
                    onChange={(e) => setNewPassword(e.target.value)}
                    className="w-full px-4 py-4 rounded-xl border-2 border-slate-100 bg-white focus:border-black outline-none text-sm font-bold transition-all text-slate-900 placeholder:text-slate-300"
                  />
                  <button onClick={() => setShowNew(!showNew)} className="absolute right-4 top-1/2 -translate-y-1/2 text-slate-400">
                    {showNew ? <EyeOff size={18} /> : <Eye size={18} />}
                  </button>
                </div>

                <div className="relative">
                  <input
                    type={showConfirm ? "text" : "password"}
                    placeholder="Confirm Password"
                    value={confirmPassword}
                    onChange={(e) => setConfirmPassword(e.target.value)}
                    className="w-full px-4 py-4 rounded-xl border-2 border-slate-100 bg-white focus:border-black outline-none text-sm font-bold transition-all text-slate-900 placeholder:text-slate-300"
                  />
                  <button onClick={() => setShowConfirm(!showConfirm)} className="absolute right-4 top-1/2 -translate-y-1/2 text-slate-400">
                    {showConfirm ? <EyeOff size={18} /> : <Eye size={18} />}
                  </button>
                </div>

                {/* FIXED ALERTS: Red for errors, Green for success */}
                {passwordMsg && (
                  <p className={`text-[10px] font-black uppercase text-center animate-pulse ${passwordMsg.includes("success") ? "text-emerald-600" : "text-rose-600"}`}>
                    {passwordMsg}
                  </p>
                )}

                <button
                  onClick={handleChangePassword}
                  disabled={loading}
                  className="w-full py-4 rounded-xl font-black text-white text-xs uppercase tracking-[0.2em] transition-all active:scale-95 shadow-lg hover:opacity-90 disabled:opacity-50 mt-2"
                  style={{ backgroundColor: brandGreen }}
                >
                  {loading ? "Updating..." : "Confirm Update"}
                </button>
              </div>
            </div>
          </div>
        </div>
      )}

      <style>{`
        .custom-scrollbar::-webkit-scrollbar { width: 4px; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: #cbd5e1; border-radius: 10px; }
      `}</style>
    </div>
  );
}

// --- STYLES ---
const styles = {};

export default FranchiseSettingsCard;

import React, { useState, useEffect, useRef, useMemo, useCallback } from "react";
import { useNavigate, useLocation } from "react-router-dom";
import {
  ArrowLeft, Search, Loader2, RefreshCw, PowerOff,
  Calendar, Timer, LogIn, LogOut, Hourglass
} from "lucide-react";
import { supabase } from "../../supabase/supabaseClient";

const THEME_GREEN = "rgb(0, 100, 55)";
const BG_GRAY = "#f8fafc";
const TEXT_DARK = "#1e293b";
const BORDER_COLOR = "#e2e8f0";

const LoginTimings = () => {
  const navigate = useNavigate();
  const location = useLocation();
  const { targetUserId } = location.state || {};

  const CACHE_KEY_LOGS = `logs_${targetUserId || 'all'}`;
  const CACHE_KEY_CONTEXT = `user_context`;

  const [logs, setLogs] = useState(() => {
    const cached = sessionStorage.getItem(CACHE_KEY_LOGS);
    return cached ? JSON.parse(cached) : [];
  });

  const [loading, setLoading] = useState(() => !sessionStorage.getItem(CACHE_KEY_LOGS));
  const [isRefreshing, setIsRefreshing] = useState(false);

  // Responsive State - Upgraded to 1024 for Tablet Support
  const [windowWidth, setWindowWidth] = useState(window.innerWidth);
  const isMobile = windowWidth < 1024;

  const [franchiseId, setFranchiseId] = useState("");

  const [searchTerm, setSearchTerm] = useState("");
  const [filterType, setFilterType] = useState("date");
  const [selectedDate, setSelectedDate] = useState(new Date().toLocaleDateString('en-CA'));
  const [startDate, setStartDate] = useState(new Date().toLocaleDateString('en-CA'));
  const [endDate, setEndDate] = useState(new Date().toLocaleDateString('en-CA'));

  const channelRef = useRef(null);
  const isMounted = useRef(true);

  // --- SCROLL TO TOP ON LOAD ---
  useEffect(() => {
    window.scrollTo(0, 0);
  }, []);

  const cleanupRealtime = useCallback(async () => {
    if (channelRef.current) {
      const channel = channelRef.current;
      channelRef.current = null;
      try {
        await supabase.removeChannel(channel);
      } catch (err) {
        // Quietly handle websocket closure during unmount
      }
    }
  }, []);

  useEffect(() => {
    isMounted.current = true;
    const handleResize = () => setWindowWidth(window.innerWidth);
    window.addEventListener('resize', handleResize);

    initFlow();

    return () => {
      isMounted.current = false;
      window.removeEventListener('resize', handleResize);
      cleanupRealtime();
    };
  }, [targetUserId, cleanupRealtime]);

  const initFlow = async () => {
    try {
      let fid = "";
      let role = "";
      let userId = "";

      const cachedContext = sessionStorage.getItem(CACHE_KEY_CONTEXT);
      if (cachedContext) {
        const parsed = JSON.parse(cachedContext);
        fid = parsed.fid;
        role = parsed.role;
        userId = parsed.userId;
        if (isMounted.current) setFranchiseId(fid);
      } else {
        const { data: { user } } = await supabase.auth.getUser();
        if (!user) return;
        userId = user.id;

        const [ownerCheck, staffCheck] = await Promise.all([
          supabase.from('profiles').select('franchise_id').eq('id', user.id).maybeSingle(),
          supabase.from('staff_profiles').select('franchise_id').eq('id', user.id).maybeSingle()
        ]);

        fid = ownerCheck.data?.franchise_id || staffCheck.data?.franchise_id;
        role = ownerCheck.data ? 'owner' : 'staff';

        if (fid && isMounted.current) {
          setFranchiseId(fid);
          sessionStorage.setItem(CACHE_KEY_CONTEXT, JSON.stringify({ fid, role, userId }));
        }
      }

      if (fid && isMounted.current) {
        fetchLogs(fid, role, userId, logs.length > 0);
        setupRealtime(fid, role, userId);
      }
    } catch (e) {
      if (isMounted.current) setLoading(false);
    }
  };

  const fetchLogs = async (fid, role, uid, silent = false) => {
    if (!isMounted.current) return;
    if (!silent) setLoading(true);
    setIsRefreshing(true);
    try {
      let query = supabase
        .from('login_logs')
        .select(`
          *,
          staff_profiles!login_logs_staff_profile_id_fkey (name, staff_id),
          profiles!login_logs_owner_profile_id_fkey (name, company)
        `)
        .eq('franchise_id', fid)
        .order('login_at', { ascending: false })
        .limit(100);

      if (targetUserId) {
        query = query.or(`staff_profile_id.eq.${targetUserId},owner_profile_id.eq.${targetUserId}`);
      } else if (role === 'staff') {
        query = query.eq('staff_id', uid);
      }

      const { data, error } = await query;

      if (!error && isMounted.current) {
        setLogs(data || []);
        sessionStorage.setItem(CACHE_KEY_LOGS, JSON.stringify(data || []));
      }
    } finally {
      if (isMounted.current) {
        setLoading(false);
        setIsRefreshing(false);
      }
    }
  };

  const setupRealtime = (fid, role, uid) => {
    if (channelRef.current) return;

    const channel = supabase
      .channel(`logs-${fid}-${Date.now()}`)
      .on('postgres_changes', { event: '*', schema: 'public', table: 'login_logs', filter: `franchise_id=eq.${fid}` },
        () => {
          if (isMounted.current) fetchLogs(fid, role, uid, true);
        })
      .subscribe();

    channelRef.current = channel;
  };

  const handleForceLogout = async (logId) => {
    if (!window.confirm("⚠️ Force end this session?")) return;
    try {
      const { error } = await supabase
        .from('login_logs')
        .update({ logout_at: new Date().toISOString() })
        .eq('id', logId);
      if (error) throw error;
    } catch (err) {
      alert("❌ Error: " + err.message);
    }
  };

  const getLogDetails = useCallback((log) => {
    let isOwner = false;
    let name = "Unknown";
    let id = "N/A";

    if (log.owner_profile_id) {
      isOwner = true;
      name = log.profiles?.name || log.profiles?.company || "Owner";
      id = "OWNER";
    }
    else if (log.staff_profile_id) {
      isOwner = false;
      name = log.staff_profiles?.name || "Staff Member";
      id = log.staff_profiles?.staff_id || "N/A";
    }

    const actualMode = log.login_mode ? log.login_mode.toUpperCase() : "STORE";

    return { name, id, isOwner, actualMode };
  }, []);

  const calculateDurationDisplay = (startStr, endStr) => {
    if (!endStr) return "Active";
    const start = new Date(startStr);
    const end = new Date(endStr);
    const diff = Math.max(0, end - start);
    const hours = Math.floor(diff / (1000 * 60 * 60));
    const mins = Math.floor((diff % (1000 * 60 * 60)) / (1000 * 60));
    if (hours === 0 && mins === 0) return "< 1m";
    return `${hours}h ${mins}m`;
  };

  const formatTime = (dateString) => {
    if (!dateString) return "---";
    return new Date(dateString).toLocaleTimeString('en-US', {
      hour: 'numeric', minute: '2-digit', hour12: true
    });
  };

  const finalLogs = useMemo(() => {
    return logs.filter(log => {
      const { name, id } = getLogDetails(log);
      const matchesSearch = (name || "").toLowerCase().includes(searchTerm.toLowerCase()) ||
        (id || "").toLowerCase().includes(searchTerm.toLowerCase());

      const logDate = new Date(log.login_at).toLocaleDateString('en-CA');
      return matchesSearch && (filterType === 'date' ? logDate === selectedDate : (logDate >= startDate && logDate <= endDate));
    });
  }, [logs, searchTerm, filterType, selectedDate, startDate, endDate, getLogDetails]);

  const stats = useMemo(() => {
    let totalSeconds = 0;
    finalLogs.forEach(log => {
      const start = new Date(log.login_at).getTime();
      let diffInSeconds = 0;
      if (log.logout_at) {
        const end = new Date(log.logout_at).getTime();
        diffInSeconds = (end - start) / 1000;
      } else {
        const end = Date.now();
        diffInSeconds = (end - start) / 1000;
        if (diffInSeconds > 86400) diffInSeconds = 0;
      }
      if (diffInSeconds > 0) totalSeconds += diffInSeconds;
    });
    const hours = Math.floor(totalSeconds / 3600);
    const minutes = Math.floor((totalSeconds % 3600) / 60);
    return { totalDuration: `${hours}h ${minutes}m` };
  }, [finalLogs]);

  return (
    <div style={styles.page}>
      <header style={styles.header}>
        <div style={styles.headerInner}>
          <button onClick={() => navigate(-1)} style={styles.backBtn}>
            <ArrowLeft size={18} /> <span>Back</span>
          </button>

          <h1 style={styles.heading}>
            User <span style={{ color: THEME_GREEN }}>Timings</span>
          </h1>

          <div style={styles.topRightActions}>
            <div style={styles.idBox}>
              ID: {franchiseId || "---"}
            </div>
          </div>
        </div>
      </header>

      <div style={{ ...styles.container, padding: isMobile ? '16px' : '20px' }}>
        <div style={{
          ...styles.controlsRow,
          flexDirection: isMobile ? 'column' : 'row',
          gap: isMobile ? '12px' : '20px'
        }}>
          <div style={{ ...styles.searchContainer, width: isMobile ? '100%' : '300px' }}>
            <Search size={18} color="#94a3b8" />
            <input
              placeholder="Search Name or ID..."
              style={styles.searchInput}
              value={searchTerm}
              onChange={e => setSearchTerm(e.target.value)}
            />
          </div>

          <div style={{
            ...styles.filterGroup,
            width: isMobile ? '100%' : 'auto',
            justifyContent: isMobile ? 'space-between' : 'flex-end',
            flexDirection: isMobile ? 'column' : 'row',
            alignItems: isMobile ? 'stretch' : 'center'
          }}>
            <div style={{
              ...styles.toggleContainer,
              width: isMobile ? '100%' : 'auto',
              display: 'flex'
            }}>
              <button
                style={{
                  ...(filterType === 'date' ? styles.toggleBtnActive : styles.toggleBtn),
                  flex: 1,
                  textAlign: 'center'
                }}
                onClick={() => setFilterType('date')}
              >
                Date
              </button>
              <button
                style={{
                  ...(filterType === 'range' ? styles.toggleBtnActive : styles.toggleBtn),
                  flex: 1,
                  textAlign: 'center'
                }}
                onClick={() => setFilterType('range')}
              >
                Range
              </button>
            </div>

            <div style={{
              display: 'flex',
              gap: '8px',
              alignItems: 'center',
              width: isMobile ? '100%' : 'auto',
              justifyContent: isMobile ? 'space-between' : 'flex-end'
            }}>
              {filterType === 'date' ? (
                <input
                  type="date"
                  style={{ ...styles.dateInput, width: '100%' }}
                  value={selectedDate}
                  onChange={(e) => setSelectedDate(e.target.value)}
                />
              ) : (
                <>
                  <input
                    type="date"
                    style={{ ...styles.dateInput, flex: 1, minWidth: 0 }}
                    value={startDate}
                    onChange={(e) => setStartDate(e.target.value)}
                  />
                  <span style={{ color: '#94a3b8', flexShrink: 0 }}>-</span>
                  <input
                    type="date"
                    style={{ ...styles.dateInput, flex: 1, minWidth: 0 }}
                    value={endDate}
                    onChange={(e) => setEndDate(e.target.value)}
                  />
                </>
              )}
              <button onClick={() => initFlow()} style={styles.refreshBtn} disabled={isRefreshing}>
                <RefreshCw size={18} className={isRefreshing ? "animate-spin" : ""} />
              </button>
            </div>
          </div>
        </div>

        <div style={{
          ...styles.statsRow,
          flexDirection: 'row',
        }}>
          <div style={{ ...styles.statCard, flex: 1 }}>
            <div style={styles.statIconBox}><Timer size={20} color="white" /></div>
            <div>
              <div style={styles.statLabel}>Total Hours</div>
              <div style={styles.statValue}>{stats.totalDuration}</div>
              <div style={styles.statSub}>Selected Period</div>
            </div>
          </div>
        </div>

        {loading ? (
          <div style={{ padding: '60px', textAlign: 'center' }}>
            <Loader2 className="animate-spin" size={32} style={{ margin: '0 auto', color: THEME_GREEN }} />
          </div>
        ) : finalLogs.length > 0 ? (
          isMobile ? (
            <div style={styles.cardGrid}>
              {finalLogs.map((log) => {
                const isLoggedOut = !!log.logout_at;
                const { name, id, isOwner, actualMode } = getLogDetails(log);

                return (
                  <div key={log.id} style={{ ...styles.mobileCard, borderLeft: isOwner ? `4px solid ${THEME_GREEN}` : `1px solid ${BORDER_COLOR}` }}>
                    <div style={styles.mobileCardHeader}>
                      <div style={{ display: 'flex', alignItems: 'center', gap: '6px', fontSize: '12px', fontWeight: '600', color: '#64748b' }}>
                        <Calendar size={14} /> {new Date(log.login_at).toLocaleDateString('en-GB')}
                      </div>
                      {isLoggedOut ? (
                        <span style={styles.badgeInactive}>Completed</span>
                      ) : (
                        <span style={styles.badgeActive}>Active Now</span>
                      )}
                    </div>
                    <div style={styles.mobileCardBody}>
                      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: '12px' }}>
                        <div>
                          <div style={{ display: 'flex', alignItems: 'center', gap: '8px', marginBottom: '4px', flexWrap: 'wrap' }}>
                            <div style={{ fontSize: '16px', fontWeight: '800', color: TEXT_DARK }}>{name}</div>
                            <span style={actualMode === "ADMIN" ? styles.modeAdmin : styles.modeStore}>
                              {actualMode}
                            </span>
                          </div>
                          <div style={{ fontSize: '12px', color: '#64748b', fontFamily: 'monospace' }}>ID: {id}</div>
                        </div>
                        {!isLoggedOut && (
                          <button onClick={() => handleForceLogout(log.id)} style={styles.mobileForceBtn}>
                            <PowerOff size={14} /> <span style={styles.hideOnVerySmall}>End</span>
                          </button>
                        )}
                      </div>
                      <div style={styles.mobileTimeGrid}>
                        <div style={styles.mobileTimeItem}>
                          <span style={styles.mobileTimeLabel}><LogIn size={10} /> Login</span>
                          <span style={{ color: THEME_GREEN, fontWeight: '700' }}>{formatTime(log.login_at)}</span>
                        </div>
                        <div style={styles.mobileTimeItem}>
                          <span style={styles.mobileTimeLabel}><LogOut size={10} /> Logout</span>
                          <span style={{ color: '#ef4444', fontWeight: '700' }}>{isLoggedOut ? formatTime(log.logout_at) : '-- : --'}</span>
                        </div>
                        <div style={styles.mobileTimeItem}>
                          <span style={styles.mobileTimeLabel}><Hourglass size={10} /> Dur</span>
                          <span style={{ fontWeight: '700' }}>{calculateDurationDisplay(log.login_at, log.logout_at)}</span>
                        </div>
                      </div>
                    </div>
                  </div>
                );
              })}
            </div>
          ) : (
            <div style={styles.tableCard}>
              <div style={styles.tableResponsiveWrapper}>
                <table style={styles.table}>
                  <thead>
                    <tr>
                      <th style={styles.th}>DATE</th>
                      <th style={styles.th}>TYPE</th>
                      <th style={styles.th}>NAME</th>
                      <th style={styles.th}>ID</th>
                      <th style={styles.th}>LOGIN</th>
                      <th style={styles.th}>LOGOUT</th>
                      <th style={styles.th}>DURATION</th>
                      <th style={styles.th}>MODE</th>
                      <th style={{ ...styles.th, textAlign: 'center' }}>STATUS</th>
                    </tr>
                  </thead>
                  <tbody>
                    {finalLogs.map((log) => {
                      const isLoggedOut = !!log.logout_at;
                      const { name, id, isOwner, actualMode } = getLogDetails(log);

                      return (
                        <tr key={log.id} style={styles.tr}>
                          <td style={styles.td}>
                            <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}><Calendar size={14} color="#64748b" />{new Date(log.login_at).toLocaleDateString('en-GB')}</div>
                          </td>
                          <td style={styles.td}>
                            <span style={{ color: isOwner ? THEME_GREEN : '#64748b', fontWeight: '800', fontSize: '11px' }}>
                              {isOwner ? "OWNER" : "STAFF"}
                            </span>
                          </td>
                          <td style={{ ...styles.td, fontWeight: '700', color: TEXT_DARK }}>{name}</td>
                          <td style={styles.td}><span style={styles.monoBadge}>{id}</span></td>
                          <td style={{ ...styles.td, color: THEME_GREEN, fontWeight: '700' }}>{formatTime(log.login_at)}</td>
                          <td style={{ ...styles.td, color: '#ef4444' }}>{isLoggedOut ? formatTime(log.logout_at) : '-- : --'}</td>
                          <td style={{ ...styles.td, fontWeight: '700' }}>{calculateDurationDisplay(log.login_at, log.logout_at)}</td>
                          <td style={styles.td}>
                            <span style={actualMode === "ADMIN" ? styles.modeAdmin : styles.modeStore}>
                              {actualMode}
                            </span>
                          </td>
                          <td style={{ ...styles.td, textAlign: 'center' }}>
                            {isLoggedOut ? <span style={styles.badgeInactive}>Completed</span> : (
                              <div style={{ display: 'inline-flex', alignItems: 'center', gap: '8px' }}>
                                <span style={styles.badgeActive}>Active</span>
                                <button onClick={() => handleForceLogout(log.id)} style={styles.forceBtn} title="Force Logout"><PowerOff size={12} /></button>
                              </div>
                            )}
                          </td>
                        </tr>
                      );
                    })}
                  </tbody>
                </table>
              </div>
            </div>
          )
        ) : (
          <div style={{ padding: '40px', textAlign: 'center', color: '#64748b', background: 'white', borderRadius: '12px', border: `1px dashed ${BORDER_COLOR}` }}>
            No records found for this period.
          </div>
        )}
      </div>
    </div>
  );
};

const styles = {
  page: { background: BG_GRAY, minHeight: "100vh", fontFamily: '"Inter", sans-serif', color: TEXT_DARK, boxSizing: 'border-box', width: '100%', overflowX: 'hidden' },
  container: { maxWidth: "1400px", margin: "0 auto", boxSizing: 'border-box' },
  header: { background: '#fff', borderBottom: '1px solid #e2e8f0', position: 'relative', zIndex: 30, width: '100%', marginBottom: '24px', boxShadow: '0 1px 2px 0 rgba(0, 0, 0, 0.05)', boxSizing: 'border-box' },
