                <p className="text-[8px] whitespace-pre-wrap leading-tight">{companyDetails?.terms || "No terms available."}</p>
              </div>
            </div>
          </div>
          <div className="w-[40%] flex flex-col text-[10px]">
            <div className="flex justify-between py-1 px-2 border-b border-black"><span>Taxable</span><span>{formatCurrency(taxableAmount)}</span></div>
            <div className="flex justify-between py-1 px-2 border-b border-slate-300"><span>Total GST</span><span>{formatCurrency(data.totalGst || 0)}</span></div>
            <div className="flex justify-between py-0.5 px-2 border-b border-slate-300 text-[9px] bg-slate-50 pl-4"><span>CGST</span><span>{formatCurrency(cgst)}</span></div>
            <div className="flex justify-between py-0.5 px-2 border-b border-black text-[9px] bg-slate-50 pl-4"><span>SGST</span><span>{formatCurrency(sgst)}</span></div>
            <div className="flex justify-between py-1 px-2 border-b border-black"><span>Round Off</span><span>{formatCurrency(data.roundOff || 0)}</span></div>
            <div className="flex justify-between py-1.5 px-2 border-b-2 border-black bg-slate-200"><span className="font-black uppercase">Total</span><span className="font-black">{formatCurrency(data.roundedBill || 0)}</span></div>
            <div className="flex-1 flex flex-col justify-end p-2 text-center min-h-[50px]">
              {pageIndex < totalPages - 1 && <p className="text-[8px] mb-1 font-bold italic text-slate-500">Continued on next page...</p>}
              <p className="font-black border-t border-black pt-1 uppercase text-[8px]">Authorized Signature</p>
            </div>
          </div>
        </div>
      </div>
      <div className="absolute bottom-1 right-2 print:bottom-1.5 print:right-2 text-[9px] font-black text-black">
        Page {pageIndex + 1} of {totalPages}
      </div>
    </div>
  );
};

// --- MAIN PAGE ---
function StockOrder() {
  const navigate = useNavigate();
  const [stocks, setStocks] = useState([]);
  const [profile, setProfile] = useState(null);
  const [companyDetails, setCompanyDetails] = useState(null);
  const [isCentral, setIsCentral] = useState(false);
  const [debouncedSearch, setDebouncedSearch] = useState("");
  const [isCartOpen, setIsCartOpen] = useState(false);
  const [loadingStocks, setLoadingStocks] = useState(true);
  const [processingOrder, setProcessingOrder] = useState(false);
  const [toasts, setToasts] = useState([]);

  // Fix 3: Double-submission guard — ref is synchronous, unlike state
  const isSubmittingRef = useRef(false);

  const [search, setSearch] = useState(() => getSessionData("stock_search", ""));
  const [selectedCategory, setSelectedCategory] = useState(() => getSessionData("stock_category", "All"));
  const [showOnlyAvailable, setShowOnlyAvailable] = useState(() => getSessionData("stock_available", false));
  const [qtyInput, setQtyInput] = useState(() => getSessionData("stock_qty_input", {}));
  const [selectedUnit, setSelectedUnit] = useState(() => getSessionData("stock_selected_unit", {}));
  const [printData, setPrintData] = useState(() => getSessionData("stock_print_data", null));
  const [lastOrderId, setLastOrderId] = useState(() => getSessionData("stock_last_order_id", null));
  const [orderSuccess, setOrderSuccess] = useState(() => getSessionData("stock_order_success", false));

  useEffect(() => {
    document.body.style.overflow = (isCartOpen || orderSuccess) ? "hidden" : "";
    return () => { document.body.style.overflow = ""; };
  }, [isCartOpen, orderSuccess]);

  const [cart, setCart] = useState(() => {
    try {
      const savedCart = localStorage.getItem("stockOrderCart");
      return savedCart ? JSON.parse(savedCart) : [];
    } catch (e) { return []; }
  });

  const [notifiedItems, setNotifiedItems] = useState(() => {
    try {
      const saved = localStorage.getItem("notifiedStockItems");
      return saved ? new Set(JSON.parse(saved)) : new Set();
    } catch (e) { return new Set(); }
  });

  useEffect(() => { sessionStorage.setItem("stock_search", JSON.stringify(search)); }, [search]);
  useEffect(() => { sessionStorage.setItem("stock_category", JSON.stringify(selectedCategory)); }, [selectedCategory]);
  useEffect(() => { sessionStorage.setItem("stock_available", JSON.stringify(showOnlyAvailable)); }, [showOnlyAvailable]);
  useEffect(() => { sessionStorage.setItem("stock_qty_input", JSON.stringify(qtyInput)); }, [qtyInput]);
  useEffect(() => { sessionStorage.setItem("stock_selected_unit", JSON.stringify(selectedUnit)); }, [selectedUnit]);
  useEffect(() => { sessionStorage.setItem("stock_print_data", JSON.stringify(printData)); }, [printData]);
  useEffect(() => { sessionStorage.setItem("stock_last_order_id", JSON.stringify(lastOrderId)); }, [lastOrderId]);
  useEffect(() => { sessionStorage.setItem("stock_order_success", JSON.stringify(orderSuccess)); }, [orderSuccess]);

  useEffect(() => {
    const handler = setTimeout(() => setDebouncedSearch(search), 300);
    return () => clearTimeout(handler);
  }, [search]);

  useEffect(() => { localStorage.setItem("stockOrderCart", JSON.stringify(cart)); }, [cart]);
  useEffect(() => { localStorage.setItem("notifiedStockItems", JSON.stringify([...notifiedItems])); }, [notifiedItems]);

  const toastTimeoutsRef = useRef(new Map());

  // Cleanup all toast timeouts on unmount
  useEffect(() => {
    const timeouts = toastTimeoutsRef.current;
    return () => { timeouts.forEach(id => clearTimeout(id)); timeouts.clear(); };
  }, []);

  const addToast = useCallback((type, title, message, duration = 4000, customId = null) => {
    const id = customId || Date.now();
    setToasts(prev => {
      const others = prev.filter(t => t.id !== id);
      return [...others, { id, type, title, message }];
    });
    // Clear any existing timeout for this toast ID
    if (toastTimeoutsRef.current.has(id)) clearTimeout(toastTimeoutsRef.current.get(id));
    const timeoutId = setTimeout(() => {
      setToasts(prev => prev.filter(t => t.id !== id));
      toastTimeoutsRef.current.delete(id);
    }, duration);
    toastTimeoutsRef.current.set(id, timeoutId);
  }, []);

  const removeToast = useCallback((id) => setToasts(prev => prev.filter(t => t.id !== id)), []);

  // --- REVISED FETCH DATA WITH SPECIFIC RELATIONAL LOGIC ---
  const fetchData = useCallback(async (isBackground = false) => {
    if (!isBackground) setLoadingStocks(true);
    try {
      const { data: { user } } = await supabase.auth.getUser();
      if (user) {
        // 1. Fetch User Profile
        const { data: profileData } = await supabase.from("profiles").select("*").eq("id", user.id).single();
        if (profileData) {
          setProfile(profileData);
          if (profileData.role === 'central' || profileData.franchise_id === 'CENTRAL') setIsCentral(true);

          // 2. Fetch Company Details based on profile.company lookup (Strict match)
          if (profileData.company) {
            const { data: companyData } = await supabase
              .from('companies')
              .select('*')
              .eq('company_name', profileData.company) // This ensures it finds T VANAMM if the profile says so
              .single();

            if (companyData) {
              setCompanyDetails(companyData);
            }
          }
        }
      }

      const { data: stockData } = await supabase.from("stocks").select("*").eq('online_store', true).order("item_name");
      setStocks(stockData || []);
    } catch (err) {
      addToast('error', 'Sync Failed', 'Could not refresh inventory.');
    } finally { setLoadingStocks(false); }
  }, [addToast]);

  useEffect(() => {
    fetchData();
    let debounceTimer;
    const stockSubscription = supabase.channel('public:stocks').on('postgres_changes', { event: '*', schema: 'public', table: 'stocks' }, () => {
      clearTimeout(debounceTimer);
      debounceTimer = setTimeout(() => fetchData(true), 300);
    }).subscribe();
    return () => { clearTimeout(debounceTimer); supabase.removeChannel(stockSubscription); };
  }, [fetchData]);

  // Fix 8: Online/offline listener — warn user during checkout
  useEffect(() => {
    const handleOffline = () => {
      addToast('error', 'Offline', 'You appear to be offline. Please check your connection before placing an order.', 8000, 'network-status');
    };
    const handleOnline = () => {
      addToast('success', 'Back Online', 'Connection restored.', 3000, 'network-status');
    };
    window.addEventListener('offline', handleOffline);
    window.addEventListener('online', handleOnline);
    return () => {
      window.removeEventListener('offline', handleOffline);
      window.removeEventListener('online', handleOnline);
    };
  }, [addToast]);

  // Fix 5: Check for pending payment on mount (recovery from tab close/crash)
  useEffect(() => {
    const pendingPaymentId = localStorage.getItem('pendingPaymentId');
    if (pendingPaymentId) {
      addToast('success', 'Payment Received', `Your payment (${pendingPaymentId}) was received. If you don't see your order, it will be processed automatically. Contact support if needed.`, 12000);
      // Clear it — the webhook will handle recovery
      localStorage.removeItem('pendingPaymentId');
    }
  }, [addToast]);



  useEffect(() => {
    if (stocks.length === 0) return;
    setCart(prevCart => {
      let hasChanges = false;
      const updatedCart = prevCart.map(cartItem => {
        const liveItem = stocks.find(s => s.id === cartItem.id);
        if (liveItem) {
          const check = validateAndClampQty(liveItem, cartItem.qty, cartItem.cartUnit);
          if (!check.valid && check.clamped !== cartItem.qty) {
            hasChanges = true;
            return { ...cartItem, qty: check.clamped, displayQty: check.clamped };
          }
        }
        return cartItem;
      }).filter(item => item.qty > 0);
      return hasChanges ? updatedCart : prevCart;
    });
  }, [stocks]);

  const sortedCategories = useMemo(() => {
    const uniqueCats = [...new Set(stocks.map(s => s.category).filter(Boolean))].sort();
    return ["All", ...uniqueCats];
  }, [stocks]);

  const liveCart = useMemo(() => {
    return cart.map(cartItem => {
      const liveData = stocks.find(s => s.id === cartItem.id);
      return liveData ? { ...cartItem, ...liveData, qty: cartItem.qty, displayQty: cartItem.displayQty, cartUnit: cartItem.cartUnit } : cartItem;
    });
  }, [cart, stocks]);

  const calculations = useMemo(() => {
    const details = liveCart.map(item => {
      const multiplier = getPriceMultiplier(item.unit, item.cartUnit);
      const effectivePrice = item.price * multiplier;
      const subtotal = effectivePrice * item.qty;
      const gstAmt = subtotal * ((item.gst_rate || 0) / 100);
      return { ...item, effectivePrice, preciseSubtotal: subtotal, preciseGst: gstAmt };
    });
    const totalSub = details.reduce((acc, c) => acc + c.preciseSubtotal, 0);
    const totalGst = details.reduce((acc, c) => acc + c.preciseGst, 0);
    const exactBill = parseFloat((totalSub + totalGst).toFixed(2));
    const roundedBill = Math.ceil(exactBill);
    return { items: details, subtotal: totalSub, totalGst, roundedBill, roundOff: roundedBill - exactBill };
  }, [liveCart]);

  const filteredStocks = useMemo(() => {
    const baseList = stocks.filter(item => {
      const query = debouncedSearch.toLowerCase();
      const matchesSearch = item.item_name.toLowerCase().includes(query) || item.item_code?.toLowerCase().includes(query);
      const matchesCategory = selectedCategory === "All" || item.category === selectedCategory;
      const matchesAvailability = showOnlyAvailable ? Number(item.quantity) > 0 : true;
      return matchesSearch && matchesCategory && matchesAvailability;
    });
    return baseList.sort((a, b) => (Number(a.quantity) > 0 && Number(b.quantity) <= 0) ? -1 : (Number(a.quantity) <= 0 && Number(b.quantity) > 0) ? 1 : 0);
  }, [stocks, debouncedSearch, selectedCategory, showOnlyAvailable]);

  const handleUnitChange = (itemId, newUnit) => {
    const item = stocks.find(s => s.id === itemId);
    if (!item) return;
    setSelectedUnit(prev => ({ ...prev, [itemId]: newUnit }));
    const newMOQ = getMOQ(item, newUnit);
    const cartItem = cart.find(c => c.id === itemId);
    if (cartItem) {
      let newQty = Math.max(cartItem.qty, newMOQ);
      const check = validateAndClampQty(item, newQty, newUnit);
      if (!check.valid) {
        addToast('error', 'Limit Reached', check.msg, 2000, `limit-${itemId}`);
        newQty = check.clamped;
      }
      if (newQty > 0) {
        setCart(prev => prev.map(c => c.id === itemId ? { ...c, cartUnit: newUnit, qty: newQty, displayQty: newQty } : c));
        setQtyInput(prev => ({ ...prev, [itemId]: newQty }));
      } else {
        setCart(prev => prev.filter(i => i.id !== itemId));
        setQtyInput(prev => ({ ...prev, [itemId]: 0 }));
      }
    } else {
      setQtyInput(prev => ({ ...prev, [itemId]: newMOQ }));
    }
  };

  const handleQtyInputChange = (itemId, val, isStepButton = false, direction = 0) => {
    const item = stocks.find(s => s.id === itemId);
    if (!item) return;
    const currentUnit = selectedUnit[itemId] || item.unit;
    const currentVal = qtyInput[itemId] || 0;
    const moq = getMOQ(item, currentUnit);
    const isGrams = ["g", "grams", "gram", "gm", "gms", "ml", "milliliter"].includes(currentUnit.toLowerCase().trim());
    const stepSize = isGrams ? 50 : 1;
    let numVal = isStepButton ? (direction === 1 ? (currentVal === 0 ? moq : currentVal + stepSize) : (currentVal <= moq ? 0 : Math.max(0, currentVal - stepSize))) : (val === "" ? 0 : Math.max(0, Number(val)));
    const check = validateAndClampQty(item, numVal, currentUnit);
    if (!check.valid) {
      addToast('error', 'Limit Reached', check.msg, 2000, `limit-${itemId}`);
      numVal = check.clamped;
    }
    setQtyInput(prev => ({ ...prev, [itemId]: numVal }));
  };

  const updateCartQty = (itemId, delta) => {
    setCart(prev => {
      let updatedCart = prev.map(item => {
        if (item.id === itemId) {
          const isGrams = ["g", "grams", "gram", "gm", "gms", "ml", "milliliter"].includes(item.cartUnit.toLowerCase().trim());
          const step = isGrams ? 50 : 1;
          const stockItem = stocks.find(s => s.id === itemId);
          const moq = getMOQ(stockItem, item.cartUnit);
          let newQty = delta === 1 ? item.qty + step : (item.qty <= moq ? 0 : item.qty - step);
          if (newQty <= 0) return null;
          if (stockItem) {
            const check = validateAndClampQty(stockItem, newQty, item.cartUnit);
            if (!check.valid) {
              addToast('error', 'Limit Reached', check.msg);
              return { ...item, qty: check.clamped, displayQty: check.clamped };
            }
          }
          return { ...item, qty: newQty, displayQty: newQty };
        }
        return item;
      }).filter(Boolean);
      if (!updatedCart.find(i => i.id === itemId)) setQtyInput(qPrev => ({ ...qPrev, [itemId]: 0 }));
      return updatedCart;
    });
  };

  const handleAddToCart = (itemId) => {
    const item = stocks.find(s => s.id === itemId);
    if (cart.some(c => c.id === itemId)) {
      updateCartQty(itemId, 1);
    } else {
      const unit = selectedUnit[itemId] || item.unit;
      const moq = getMOQ(item, unit);
      let qtyToAdd = Math.max(qtyInput[itemId] || 0, moq);
      const check = validateAndClampQty(item, qtyToAdd, unit);
      if (!check.valid) {
        addToast('error', 'Limit Reached', check.msg);
        qtyToAdd = check.clamped;
      }
      if (qtyToAdd > 0) {
        setCart(prev => [...prev, { ...item, qty: qtyToAdd, displayQty: qtyToAdd, cartUnit: unit }]);
        setQtyInput(prev => ({ ...prev, [itemId]: qtyToAdd }));
      }
    }
  };

  const removeFromCart = (id) => {
    setCart(prev => prev.filter(i => i.id !== id));
    setQtyInput(prev => ({ ...prev, [id]: 0 }));
  };

  const handleManualInputCart = (item, val) => {
    const numVal = val === "" ? 0 : Math.max(0, Number(val));
    if (numVal === 0) {
      removeFromCart(item.id);
      return;
    }
    const stockItem = stocks.find(s => s.id === item.id);
    if (stockItem) {
      const check = validateAndClampQty(stockItem, numVal, item.cartUnit);
      if (!check.valid) {
        addToast('error', 'Limit Reached', check.msg, 2000, `limit-${item.id}`);
        setCart(prev => prev.map(c => c.id === item.id ? { ...c, qty: check.clamped, displayQty: check.clamped } : c));
        return;
      }
    }
    setCart(prev => prev.map(c => c.id === item.id ? { ...c, qty: numVal, displayQty: numVal } : c));
  };

  const handleNotifyMe = async (item) => {
    if (notifiedItems.has(item.id)) return;
    try {
      const { data: { user } } = await supabase.auth.getUser();
      if (!user) return addToast('error', 'Login Required', 'Please log in.');
      await supabase.from("stock_requests").insert([{ stock_id: item.id, item_name: item.item_name, franchise_id: profile?.franchise_id || "N/A", user_id: user.id, user_name: profile?.name || "User", status: 'pending' }]);
      setNotifiedItems(prev => new Set(prev).add(item.id));
      addToast('success', 'Requested', `We'll notify you for ${item.item_name}`);
    } catch (e) { addToast('error', 'Failed', e.message); }
  };

  const handlePlaceOrder = async () => {
    if (cart.length === 0) return;

    // Fix 3: Synchronous double-submission guard
    if (isSubmittingRef.current) return;
    isSubmittingRef.current = true;
    setProcessingOrder(true);

    try {
      // Fix 4: Pre-flight network check
      if (typeof navigator !== 'undefined' && !navigator.onLine) {
        throw new Error("You appear to be offline. Please check your internet connection and try again.");
      }

      const { data: { user } } = await supabase.auth.getUser();
      if (!user || !profile) throw new Error("Authentication failed. Please log in again.");

      const orderItems = calculations.items.map(i => ({
        stock_id: i.id,
        item_name: i.item_name,
        quantity: i.qty,
        unit: i.cartUnit,
        price: i.effectivePrice,
        gst_rate: i.gst_rate
      }));

      // Fix 9: Stale stock guard — re-fetch live quantities before payment
      const cartStockIds = cart.map(c => c.id);
      const { data: freshStocks, error: freshError } = await supabase
        .from('stocks')
        .select('id, quantity, item_name, unit')
        .in('id', cartStockIds);

      if (freshError) throw new Error("Could not verify stock availability. Please try again.");

      const stockIssues = [];
      for (const cartItem of cart) {
        const fresh = freshStocks?.find(s => s.id === cartItem.id);
        if (!fresh) {
          stockIssues.push(`${cartItem.item_name} is no longer available.`);
          continue;
        }
        const factor = getPriceMultiplier(fresh.unit, cartItem.cartUnit);
        const neededBaseQty = cartItem.qty * factor;
        if (neededBaseQty > Number(fresh.quantity)) {
          stockIssues.push(`${cartItem.item_name}: only ${fresh.quantity} ${fresh.unit} left (you need ${neededBaseQty} ${fresh.unit}).`);
        }
      }

      if (stockIssues.length > 0) {
        // Update stocks state so UI reflects reality
        if (freshStocks) setStocks(prev => prev.map(s => {
          const updated = freshStocks.find(f => f.id === s.id);
          return updated ? { ...s, quantity: updated.quantity } : s;
        }));
        throw new Error(`Stock changed: ${stockIssues[0]}`);
      }

      const isScriptLoaded = await loadRazorpayScript();
      if (!isScriptLoaded) throw new Error("Payment gateway could not be loaded. Please refresh and try again.");

      // Fix 1: Build Razorpay notes for webhook recovery
      const razorpayNotes = {
        user_id: user.id,
        customer_name: profile.name,
        customer_email: profile.email,
        customer_phone: profile.phone || "",
        customer_address: profile.address || "",
        franchise_id: profile.franchise_id || "N/A",
        items: JSON.stringify(orderItems)
      };

      const options = {
        key: RAZORPAY_KEY_ID,
        amount: Math.round(calculations.roundedBill * 100),
        currency: "INR",
        name: companyDetails?.company_name || "Tvanamm",
        notes: razorpayNotes, // Fix 1: Enable webhook recovery
        handler: async (response) => {
          const paymentId = response.razorpay_payment_id;
          const successTime = new Date();
          const formattedTime = successTime.toLocaleTimeString('en-US', { hour: '2-digit', minute: '2-digit', second: '2-digit', hour12: true });

          // Fix 5: Persist payment ID immediately for crash recovery
          try { localStorage.setItem('pendingPaymentId', paymentId); } catch (e) { /* storage full, non-critical */ }

          // Fix 2: Retry the DB call with exponential backoff
          const MAX_DB_RETRIES = 3;
          let result = null;
          let lastDbError = null;

          for (let attempt = 0; attempt < MAX_DB_RETRIES; attempt++) {
            try {
              const { data, error: rpcError } = await supabase.rpc('place_stock_order', {
                p_created_by: user.id,
                p_customer_name: profile.name,
                p_customer_email: profile.email,
                p_customer_phone: profile.phone,
                p_customer_address: profile.address,
                p_branch_location: profile.branch_location || "",
                p_franchise_id: profile.franchise_id,
                p_payment_id: paymentId,
                p_items: orderItems,
                p_subtotal: calculations.subtotal,
                p_tax_amount: calculations.totalGst,
                p_round_off: calculations.roundOff,
                p_total_amount: calculations.roundedBill,
                p_order_time: formattedTime,
                p_snapshot_company_name: companyDetails?.company_name || "",
                p_snapshot_company_address: companyDetails?.company_address || "",
                p_snapshot_company_gst: companyDetails?.company_gst || "",
                p_snapshot_bank_details: {
                  bank_name: companyDetails?.bank_name || "",
                  bank_acc_no: companyDetails?.bank_acc_no || "",
                  bank_ifsc: companyDetails?.bank_ifsc || ""
                },
                p_snapshot_terms: companyDetails?.terms || ""
              });

              if (rpcError) {
                // If it's a network error, retry; if it's a business logic error, fail immediately
                if (isNetworkError(rpcError) && attempt < MAX_DB_RETRIES - 1) {
                  lastDbError = rpcError;
                  const delay = 1000 * Math.pow(2, attempt); // 1s, 2s, 4s
                  console.warn(`[Order] DB attempt ${attempt + 1} failed (network). Retrying in ${delay}ms...`);
                  await new Promise(r => setTimeout(r, delay));
                  continue;
                }
                throw rpcError;
              }

              result = data;
              break; // Success!
            } catch (retryErr) {
              lastDbError = retryErr;
              if (isNetworkError(retryErr) && attempt < MAX_DB_RETRIES - 1) {
                const delay = 1000 * Math.pow(2, attempt);
                console.warn(`[Order] DB attempt ${attempt + 1} threw (network). Retrying in ${delay}ms...`);
                await new Promise(r => setTimeout(r, delay));
                continue;
              }
              // Non-network error or last attempt — break out
              break;
            }
          }

          // Fix 2: If all retries failed, show calming message (webhook will recover)
          if (!result) {
            console.error('[Order] All DB retries exhausted. Payment ID:', paymentId, 'Error:', lastDbError);
            addToast('success', 'Payment Received!',
              'Your payment was successful. Your order is being processed and will appear shortly. If it doesn\'t appear within 10 minutes, please contact support with payment ID: ' + paymentId,
              15000
            );
            setProcessingOrder(false);
            isSubmittingRef.current = false;
            // Fix 5: Keep pendingPaymentId in localStorage for next page load recovery
            setCart([]);
            setQtyInput({});
            setIsCartOpen(false);
            fetchData();
            return;
          }

          // Fix 5: DB succeeded — clear pending payment
          try { localStorage.removeItem('pendingPaymentId'); } catch (e) { /* non-critical */ }

          // --- Invoice PDF generation (unchanged) ---
          const currentPrintChunks = [];
          for (let i = 0; i < calculations.items.length; i += ITEMS_PER_INVOICE_PAGE) {
            currentPrintChunks.push(calculations.items.slice(i, i + ITEMS_PER_INVOICE_PAGE));
          }
          const invoiceHtmlRaw = currentPrintChunks.map((chunk, index) => {
            return renderToStaticMarkup(
              <FullPageInvoice
                data={{ ...calculations, roundedBill: result.real_amount }}
                profile={profile}
                orderId={result.order_id}
                companyDetails={companyDetails}
                itemsChunk={chunk}
                pageIndex={index}
                totalPages={currentPrintChunks.length}
              />
            );
          }).join("");
          const tempDiv = document.createElement("div");
          tempDiv.style.cssText = "position: absolute; top: -10000px; left: -10000px; width: 794px; background: white; z-index: -100;";
          tempDiv.innerHTML = getEmailStyles() + invoiceHtmlRaw;
          document.body.appendChild(tempDiv);
          let pdfBase64;
          try {
            await new Promise(resolve => setTimeout(resolve, 800));
            const pdf = new jsPDF("p", "mm", "a4");
            const pages = tempDiv.querySelectorAll('.a4-page');
            for (let i = 0; i < pages.length; i++) {
              const canvas = await html2canvas(pages[i], {
                scale: 2,
                useCORS: true,
                backgroundColor: "#ffffff",
                width: 794,
                height: 1122,
                windowWidth: 794,
                onclone: (documentClone) => {
                  const element = documentClone.querySelectorAll('.a4-page')[i];
                  element.style.margin = "0";
                  element.style.boxShadow = "none";
                  element.style.transform = "none";
                }
              });
              const imgData = canvas.toDataURL("image/jpeg", 1.0);
              if (i > 0) pdf.addPage();
              const pdfWidth = pdf.internal.pageSize.getWidth();
              const pdfHeight = pdf.internal.pageSize.getHeight();
              pdf.addImage(imgData, "JPEG", 0, 0, pdfWidth, pdfHeight);
            }
            pdfBase64 = pdf.output('datauristring').split(',')[1];
          } finally {
            document.body.removeChild(tempDiv);
          }

          // Fix 7: Email — proper error checking (matching Registeruser.jsx pattern)
          try {
            const simpleEmailHtml = `
              <div style="font-family: sans-serif; padding: 20px; color: #333;">
                <h2 style="color: #006437;">Order Confirmation #${result.order_id}</h2>
                <p>Hi ${profile.name},</p>
                <p>Thank you for your order. Please find your detailed tax invoice attached as a PDF.</p>
                <p><strong>Total Amount: ${formatCurrency(calculations.roundedBill)}</strong></p>
                <br/>
                <p>Best regards,<br/>${companyDetails?.company_name || 'Tvanamm'}</p>
              </div>
            `;

            // Force-refresh session to get a fresh JWT (Razorpay payment flow may take minutes, staling the token)
            const { data: { session: freshSession } } = await supabase.auth.refreshSession();

            const { data: emailData, error: emailError } = await supabase.functions.invoke('send-invoice-email', {
              body: {
                orderId: result.order_id,
                userEmail: profile.email,
                customerName: profile.name,
                htmlBody: simpleEmailHtml,
                pdfAttachment: pdfBase64
              },
              headers: freshSession?.access_token ? { Authorization: `Bearer ${freshSession.access_token}` } : {},
            });

            // Check for network/auth-level error from supabase.functions.invoke
            if (emailError) {
              console.error("Full emailError object:", JSON.stringify(emailError, null, 2));
              console.error("emailError.context:", emailError.context);
              let msg = emailError.message || "Failed to call email function.";
              try {
                if (emailError.context && typeof emailError.context.json === 'function') {
                  const body = await emailError.context.json();
                  console.error("Edge function response body:", body);
                  if (body?.error) msg = body.error;
                } else if (emailError.context && typeof emailError.context === 'object') {
                  console.error("Edge function context (object):", emailError.context);
                  if (emailError.context.error) msg = emailError.context.error;
                }
              } catch (parseErr) {
                console.error("Could not parse error context:", parseErr);
              }
              console.error("Edge Function invoke error:", msg);
              throw new Error(msg);
            }

            // Check for application-level error from the edge function response
            if (emailData?.error) {
              console.error("Resend API error:", emailData.error);
              throw new Error(emailData.error);
            }

            console.log("✅ Invoice email sent successfully:", emailData);
          } catch (efErr) {
            console.error("Email sending failed:", efErr);
            addToast('error', 'Email Failed', `Invoice email could not be sent: ${efErr.message || 'Unknown error'}. You can download the invoice from the success screen.`, 8000);
          }

          setLastOrderId(result.order_id);
          setPrintData({ ...calculations, roundedBill: result.real_amount, orderTime: formattedTime });
          setOrderSuccess(true);
          setProcessingOrder(false);
          isSubmittingRef.current = false;
          fetchData();
          setCart([]);
          setQtyInput({});
          setIsCartOpen(false);
        },
        prefill: { name: profile.name, email: profile.email, contact: profile.phone },
        theme: { color: BRAND_COLOR },
        // Fix 6: Robust ondismiss cleanup including ref
        modal: {
          ondismiss: () => {
            setProcessingOrder(false);
            isSubmittingRef.current = false;
          }
        }
      };
      new window.Razorpay(options).open();
    } catch (error) {
