    const unitOptions = useMemo(() => {
        const opts = [formData.unit];
        if (formData.alt_unit && formData.alt_unit !== "None" && formData.alt_unit !== formData.unit) {
            opts.push(formData.alt_unit);
        }
        return opts;
    }, [formData.unit, formData.alt_unit]);

