                                    <div className="col-span-1">
                                        <LabeledInput
                                            label="MOQ (Alt Unit)"
                                            name="min_order_quantity_alt"
                                            value={formData.min_order_quantity_alt}
                                            onChange={(e) => setFormData({ ...formData, min_order_quantity_alt: e.target.value })}
