const getSessionItem = (key) => {
    try {
        const item = sessionStorage.getItem(key);
        return item ? JSON.parse(item) : null;
    } catch { return null; }
};

const setSessionItem = (key, value) => {
    try { sessionStorage.setItem(key, JSON.stringify(value)); } catch { }
};

