                <div style={{ display: 'flex', gap: '8px', width: '100%', height: '100%' }}>
                  <button style={{ ...styles.connectedBadge, flex: 1 }}>
                    <Printer size={16} /> {isMobile ? "ON" : "CONNECTED"}
